window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q06"]=window.__LIBQ["tien-nghich"]["q06"]||{};window.__LIBQ["tien-nghich"]["q06"]["characters"]={"updatedAt":"2026-06-16","count":43,"chars":[{"id":"vuong-lam","name":"Vương Lâm","gioiTinh":"nam","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0458","importance":"normal","tieuDe":"Lấy toàn bộ tiên ngọc Phẩm Linh Các","text":"Với thân phận Đệ thất tử Tử hệ đã 103 năm chưa lĩnh tiên ngọc, Vương Lâm vào tiên cảnh tầng bảy Phẩm Linh Các, chọn lấy toàn bộ và thu trọn 123.600 khối tiên ngọc cao như núi vào túi trữ vật, định bế quan trong ba tháng để đột phá Anh Biến trung kỳ, tranh đoạt danh hiệu thiên vận thất tử."},{"chuong":"@c0458","importance":"normal","tieuDe":"Năm người vây kích tại Tử Lâm Các","text":"Vừa về Tử Lâm Các, hắn bị năm người hợp vây gồm tứ sư tỷ Tử hệ, Triệu Tinh Sát, đệ tử thứ hai Lam tông, Tư Mã Như Phong và một người y phục xanh nửa bước vấn đỉnh; tứ sư tỷ bắt quyết thi triển Tử thuật - Na di bao trùm mười dặm để khởi chiến."},{"chuong":"@c0459","importance":"normal","tieuDe":"Bị vây khốn thạch lâm khốn địa","text":"Vương Lâm bị tứ sư tỷ cùng Triệu Tinh Sát, nhị sư huynh và hai người Thanh-Lam hai hệ liên thủ khóa không gian, phát bốn đạo sát khí chấn nhiếp rồi na di tới thạch lâm khốn địa ngoài Thiên Vận Tông hơn mười ngàn dặm. Tứ sư tỷ hẹn ba năm sau tới thả ra, để hắn yên tĩnh bế quan."},{"bridge":true,"khoang":"@c0459–@c0459","text":"Hắn thử phá vây nhiều cách — chém kiếm quang bằng tiên kiếm, bay thẳng lên trên chịu lực cản tương đương Anh Biến hậu kỳ, rồi cho Hứa Lập Quốc và loan đao lao thử — đều bị trận pháp triệt tiêu."},{"chuong":"@c0459","importance":"normal","tieuDe":"Quyết tu luyện đột phá Anh Biến trung kỳ","text":"Nhận ra kẻ địch định vây tới khi tranh đoạt danh hiệu Thiên Vận Thất Tử kết thúc, Vương Lâm quyết không chờ ba năm mà tự phá nơi này. Hắn tìm được biên giới thạch lâm, ngồi khoanh chân hấp thu lượng lớn tiên ngọc luyện công, sau lưng hiện quầng sáng vàng báo hiệu tiên lực đạt bão hòa."},{"chuong":"@c0460","importance":"normal","tieuDe":"Hoàn tất hấp thu tiên lực","text":"Toàn bộ tiên lực điên cuồng nhập thể, Vương Lâm dồn toàn lực hấp thu suốt ba tháng tại thạch lâm cách Thiên Vận Tông hơn mười ngàn dặm."},{"chuong":"@c0460","importance":"normal","tieuDe":"Đột phá chấn thiên địa","text":"Mở mắt phát hai luồng quang như trăng rằm, một cái nhấn tay làm thạch lâm mười dặm tan thành bụi; há miệng hút thu khí tức như phễu rồi thét dài chấn động thiên địa, vụt đứng dậy dáng như đội trời đạp đất."},{"chuong":"@c0461","importance":"normal","tieuDe":"Phá trận thoát thạch lâm","text":"Sau ba tháng bị tấm màn sáng hình vòm vây khốn trong thạch lâm rộng mười dặm, Vương Lâm bay lên sát đỉnh màn, dùng Tịch Diệt Chỉ điểm tạo vô số vết nứt nhưng trận tự khôi phục; hắn chuyển sang Hóa Ma Chỉ nghịch hóa toàn bộ tiên lực thành ma hỏa tím, thiêu rụi cả tấm màn chỉ trong ba nhịp thở."},{"chuong":"@c0461","importance":"normal","tieuDe":"Trở về Thiên Vận Tông báo thù","text":"Không thuộc địa hình, Vương Lâm thả nguyên thần Tào Nhất Đấu dẫn đường, thuấn di ba mươi vạn dặm về hướng tây; hồi tưởng bị Tử hệ nhất mạch chèn ép na di vây khốn, hắn lập thề ai phạm ta giết không tha, xuất hiện thành cầu vồng tím từ đằng đông ngay giữa thọ yến ngàn năm của Thiên Vận Tử đúng lúc Triệu Tinh Sát chúc rượu."},{"chuong":"@c0462","importance":"normal","tieuDe":"Xông vào thọ yến truy sát kẻ thù","text":"Cưỡi đám mây tím phá không tới Tử Tông Sơn trên Thiên Vận Tinh, kinh động cả buổi thọ yến của sư tôn Tử hệ. Hắn dùng Cấm Phiên xé tan Thượng chi lực của nhị sư huynh, cảnh cáo các tu sĩ tông phái khác không được can dự, rồi khơi ma hỏa quyết tâm đòi mạng."},{"chuong":"@c0462","importance":"normal","tieuDe":"Ma hỏa tự bạo phá quyết Triệu Tinh Sát","text":"Khi Triệu Tinh Sát bước ra dùng Đại tự tại thiên địa quyết bọc ma hỏa hòng cản, Vương Lâm hô “Bạo”, ma hỏa tự nổ phát tiết ma khí và lửa tím, thiêu vỡ quầng sáng trắng, quét nghìn trượng tạo hố lớn khiến mọi tu sĩ tản chạy."},{"chuong":"@c0462","importance":"normal","tieuDe":"Đả thương nguyên thần Hứa Lập Quốc","text":"Vương Lâm vung tiên kiếm và loan đao chém tan màn sương đen Tiên Ma thể của Hứa Lập Quốc, rồi dùng Côn Cực Tiên kéo dài đánh trúng nguyên thần đang thuấn di trốn cách nghìn trượng, khiến nguyên thần run rẩy sắp tan, lưng hiện vết thương sâu, phát tiết lượng lớn tiên lực tinh hoa."},{"chuong":"@c0463","importance":"normal","tieuDe":"Uy hiếp Triệu Tinh Sát giữa Tử Tông","text":"Vương Lâm thu nốt nguyên thần đối phương vào Tôn Hồn Phiên rồi chỉ thẳng Triệu Tinh Sát, tuyên bố ai cản trở sẽ thành kẻ thù. Các chấp pháp trưởng lão Tử Tông do dự không ai dám tiến lên."},{"chuong":"@c0463","importance":"normal","tieuDe":"Đối đầu Cổ Yêu, triệu Hồn Thú","text":"Khi Triệu Tinh Sát triệu hư ảnh cổ yêu trăm trượng, Vương Lâm dùng Tôn Hồn Phiên thu hồi chủ hồn bị lốc xoáy đỏ hút, rồi vỗ Xạ Thần Xa triệu Hồn Thú đâm xuyên thân yêu vật. Ánh mắt lạnh thấu xương của cổ yêu khiến hắn liên tưởng tới hóa thân của cổ thần thiên đạo sứ giả."},{"bridge":true,"khoang":"@c0463–@c0463","text":"Sau khi Xích Liệt quát đuổi cổ yêu kết thúc trận, Vương Lâm điềm tĩnh thu Khu Thú Quyển, ung dung đi tới ngồi vào bàn trống thứ ba dưới chỗ tứ sư tỷ — vị trí thuộc về hắn."},{"chuong":"@c0464","importance":"normal","tieuDe":"Thay chủ yến hội Tử hệ","text":"Sau khi Xích Liệt bắt Triệu Sát Tinh đi, Vương Lâm trở thành tâm điểm yến hội ngày cuối, được các tu sĩ tông phái kéo đến chúc rượu vì nhận định hắn chắc chắn trở thành Thiên Vận Thất Tử."},{"chuong":"@c0464","importance":"normal","tieuDe":"Nhận ngọc giản hai cấm pháp","text":"Đêm khuya yến tàn, tứ sư tỷ trao ngọc giản chứa cấm pháp đại na di và một cấm pháp do sư tôn phỏng tiên thuật sáng tạo, coi như xin lỗi việc tháng trước; Vương Lâm nhận, không muốn trở mặt hoàn toàn."},{"chuong":"@c0464","importance":"normal","tieuDe":"Tu thành thuật đại na di","text":"Trong mật thất tầng ba Tử Lâm Các, Vương Lâm thử cấm pháp dịch chuyển mười vạn dặm, bước bảy bước trong hào quang bạc rồi xuất hiện trên đỉnh núi cách đó mười vạn dặm, xác nhận đã tới đúng Thiên Vận Tinh."},{"chuong":"@c0464","importance":"major","tieuDe":"Khai mở tu luyện tiên thuật","text":"Vương Lâm đặt tên Cửu Chuyển Luyện Tiên Quyết cho cấm pháp thứ hai, tu liên tiếp nhất chuyển, nhị chuyển, tam chuyển, ngưng tụ luồng kim tiên lực sắc bén ở tay trái — đánh dấu lần đầu tu thành tiên thuật chân chính nhờ đã có tiên thể bậc trung."},{"chuong":"@c0464","importance":"normal","tieuDe":"Dự lễ giảng đạo Thiên Vận Tử","text":"Trời sáng, Vương Lâm tới dự lễ giảng đạo vạn năm một lần của sư tôn; quét mắt nhận ra ba cao thủ trong sáu tông: Tư Mã Như Phong, nam tử họ Vương của Thanh Tông (nửa bước Vấn Đỉnh) và người trung niên Cam Tông từng đánh Sất Hổ."},{"chuong":"@c0465","importance":"normal","tieuDe":"Dự thọ yến vạn năm Thiên Vận Tử","text":"Với thân phận đệ tử Tử Hệ, Vương Lâm dự đại thọ vạn năm của Thiên Vận Tử, đánh giá thực lực thất hệ và nhận thấy nhiều đệ tử ẩn giấu bản lãnh, trừ ba người Tử Hệ thì các Hệ khác đều có thể hoành hành ở Chu Tước Tinh. Hắn chứng kiến Tôn trưởng lão từ tu chân liên minh giáng lâm bằng kim quang trận pháp khổng lồ."},{"bridge":true,"khoang":"@c0465","text":"Khi Thiên Vận Tử bắt đầu giảng Thiên Vận Chi Đạo, con tiểu điêu ba mắt của Tôn trưởng lão bất ngờ bay tới đậu lên vai Vương Lâm, ba mắt phát tia sáng âm u dò xét hắn; Vương Lâm thấy con chim quen quen liền chăm chú quan sát."},{"chuong":"@c0466","importance":"normal","tieuDe":"Tinh Ngân điêu tìm tới","text":"Một con tử điêu ba mắt đậu trên vai Vương Lâm; qua truyền thừa ký ức cổ thần Đồ Ti hắn nhận ra đó là Tinh Ngân điêu còn nhỏ. Con chim không màng thượng phẩm tinh thạch, chỉ chăm chú nhìn hắn vì bị khí tức cổ thần cực yếu trên người hắn thu hút, song lượng khí tức quá ít khiến hắn thất vọng."},{"chuong":"@c0466","importance":"normal","tieuDe":"Vấn đạo trước sư tôn","text":"Được Thiên Vận Tử gọi đích danh chỉ điểm trước tu sĩ bốn phía và đệ tử lục hệ, Vương Lâm cung kính hỏi cách phân biệt tu tiên, tu chân và tu đạo. Nghe sư tôn giảng ba bước tu đạo, hắn vẫn hoài nghi có thực sự tồn tại bước thứ ba hay không, dẫn tới việc Thiên Vận Tử tiết lộ về ‘hắn’."},{"bridge":true,"khoang":"@c0466–@c0466","text":"Vương Lâm thử dụ tử điêu bằng tiên ngọc; con chim đoạt nuốt liền hai khối với tốc độ khó tưởng tượng rồi đậu sang vai Tôn trưởng lão, mắt vẫn dán vào túi trữ vật của hắn."},{"chuong":"@c0467","importance":"normal","tieuDe":"Gặp lại Lăng Thiên Hầu","text":"Tại lễ đại thọ vạn năm, Vương Lâm lặng nghe trọn ba ngày giảng đạo của Thiên Vận Tử và dần có lĩnh ngộ. Hắn chứng kiến Tiên thuật lần đầu trong đời khi Thiên Vận Tử thi triển trung phẩm Dẫn Tiên thuật, đồng thời nhận ra xà hình bảo kiếm dưới chân Lăng Thiên Hầu chính là Vũ chi đệ nhị kiếm từng thấy ở Tiên giới."},{"bridge":true,"khoang":"@c0467","text":"Khi thiên uy vô thanh của Dẫn Tiên thuật giáng xuống khiến tiên lực trong người hỗn loạn, Vương Lâm vận tam chuyển kim tiên lực từ cánh tay trái lưu chuyển toàn thân, khống chế không để nó hòa lẫn tiên lực vốn có, nhờ đó dần đứng vững lại."},{"chuong":"@c0468","importance":"normal","tieuDe":"Trụ vững khảo nghiệm áp lực Tử hệ","text":"Trong khảo nghiệm áp lực phân loại đệ tử tại đại thọ Thiên Vận Tử, Vương Lâm cùng Tứ sư tỷ là hai người duy nhất của Tử hệ trụ vững; hắn vận kim tiên lực ba vòng khôi phục sắc mặt, được Tứ sư tỷ liếc nhìn đầy thâm ý."},{"chuong":"@c0468","importance":"normal","tieuDe":"Giấu Tôn Hồn Phiên trước Kỳ Lân thú","text":"Khi Lăng Thiên Hầu triệu Kỳ Lân thú từ mi tâm, Tôn Hồn Phiên trong nguyên thần Vương Lâm phát tiếng gầm rít cộng hưởng khiến Kỳ Lân thú dừng lại quét mắt tìm kiếm; hắn lập tức vận Tôn Hồn Phiên che giấu toàn bộ tàn hồn, tránh bị phát hiện."},{"bridge":true,"khoang":"@c0468","text":"Quan sát Dẫn Tiên thuật của Thiên Vận Tử, Vương Lâm lĩnh hội sâu thêm rằng Tiên thuật do hư ảo tạo thành nhưng tồn tại vĩnh hằng, chỉ cần có khẩu quyết, phương pháp và tư cách là thi triển được ở bất kỳ đâu."},{"chuong":"@c0469","importance":"normal","tieuDe":"Tranh phong hiệu, đấu Triệu Hân Mộng","text":"Vương Lâm (Lão Thất) ban đầu định bỏ cuộc tranh phong hiệu Thiên Vận Thất tử vì linh cảm điều bất thường nơi Vận Đường, nhưng bị Thiên Vận Tử đích thân khuyên giải — người thứ hai sau Tôn Vân được sư phụ khuyên — nên đổi ý quyết tranh đoạt. Hắn khai chiến với Tứ sư tỷ Triệu Hân Mộng: nàng dùng Tử Ma thủ mô phỏng từ Hoá Ma chỉ của hắn, Vương Lâm đáp trả bằng Hoá Ma chỉ khiến ma khí ngập trời gào rít bao phủ bốn phía."},{"chuong":"@c0470","importance":"normal","tieuDe":"Phá bẫy hấp thu ma lực","text":"Vương Lâm thi triển Hoá Ma chỉ đối đầu Tử Ma thủ của Triệu Hân Mộng; nàng dùng hạt châu hô ‘Thu’ hút ma lực để cướp đoạt, nhưng Vương Lâm vạch trần đây chỉ là tia hư ảo do tiên lực chuyển hoá, tâm niệm khẽ động liền khiến nó tự sụp. Hắn từ chối nhường, viện lời hứa với Tư Đồ Nam không truyền ba thức sát chiêu ra ngoài."},{"chuong":"@c0470","importance":"normal","tieuDe":"Ngũ chuyển luyện tiên trong vài ngày","text":"Đối đáp Cửu chuyển luyện tiên quyết của Triệu Hân Mộng, Vương Lâm dù mới nhận công pháp vài ngày đã lập tức tu ra tam chuyển, tứ chuyển rồi ngũ chuyển kim tiên lực, chịu đau đớn cực lớn mà thần sắc thong dong, lại rút chiến phủ Cự Ma Tộc và Xạ Thần xa uy hiếp. Triệu Hân Mộng thừa nhận đã xem thường hắn rồi bỏ cuộc."},{"chuong":"@c0470","importance":"normal","tieuDe":"Giao chiến Trần Đào","text":"Trần Đào (Vấn Đỉnh) đánh ấn quyết chấn nhiếp nhưng chỉ đẩy lùi Vương Lâm hơn mười trượng thay vì trăm trượng như dự tính. Vương Lâm phóng ngũ chuyển kim tiên lực, bị Trần Đào đẩy lên cửu chuyển phản công; hắn dùng chiến phủ chém rồi thi Đại Na Di khiến cơn lốc cửu chuyển biến mất ngay trước mặt, sau đó triệu Hồn thú từ Xạ Thần xa khiến cả trường chấn động."},{"chuong":"@c0471","importance":"normal","tieuDe":"Lần đầu mở phong ấn Xạ Thần xa","text":"Trong trận đấu với Trần Đào tại lễ chúc thọ, Vương Lâm lần đầu kết ấn mở đạo phong ấn thứ nhất của Xạ Thần xa, khiến Hồn thú bạo tăng từ mười trượng lên hơn trăm trượng và đoạt được thiên uy thần thông mới."},{"chuong":"@c0471","importance":"normal","tieuDe":"Thi triển Hoàng tuyền chỉ","text":"Biết mình không phải đối thủ Vấn Đỉnh kỳ nhưng không từ bỏ, Vương Lâm cưỡng dùng sát chiêu cuối Hoàng tuyền chỉ của Tư Đồ Nam: tiêu tan sinh mạng, hiện Sinh tử luân hồi ý cảnh, khiến toàn trường sững sờ và các đại nhân vật như Thiên Vận Tử, Lăng Thiên Hầu chú ý."},{"chuong":"@c0472","importance":"normal","tieuDe":"Bại trận trước Trần Đào","text":"Phóng hai đạo Hoàng tuyền chỉ (một từ ngón út, một từ Luân hồi ý cảnh hóa thành) công kích Trần Đào gây nổ kinh thiên động địa, nhưng Trần Đào nhờ kỳ ngộ đạt Vấn Đỉnh trung kỳ nên đỡ được. Vương Lâm bị đẩy lùi hơn trăm trượng, phun một ngụm tiên huyết, tiên lực hỗn loạn nên tuyên bố bỏ cuộc; Trần Đào do đó đoạt phong hiệu Thiên Vận Thất tử của Tử hệ."},{"chuong":"@c0472","importance":"major","tieuDe":"Thành đệ tử chân chính Thiên Vận Tử","text":"Được Thiên Vận Tử gọi theo về Tổng tông tế bái Tổ linh, hứa truyền Cấm pháp thần thông và ban pháp bảo bản mạng, chính thức trở thành đệ tử chân chính. Giải đúng câu đố ba ngọn núi (nhìn ra hai sườn núi hai bên là giả do Chân huyễn pháp) nên được đặc ân tự chọn Cấm pháp thần thông thay vì bị chỉ định."},{"chuong":"@c0472","importance":"normal","tieuDe":"Vượt kỷ lục Toái Tiên chi địa","text":"Leo ngọn núi trắng phủ Cửu U chi hàn không dùng thuấn di, đạp băng đối mặt khảo nghiệm Toái Tiên chi địa. Đi được hai mươi mốt bước (vượt xa cực hạn Anh Biến trung kỳ mà Thiên Vận Tử dự đoán), rồi bước thứ hai mươi hai và thêm năm bước nữa, tiến gần kỷ lục hai mươi sáu bước của Tôn Vân."},{"chuong":"@c0473","importance":"major","tieuDe":"Bái sư nhập Thiên Vận Tông","text":"Vương Lâm chính thức quỳ bái Thiên Vận Tử, được thu làm đệ tử thứ bảy của Tử hệ dưới ánh sáng chín màu. Hắn thề chỉ cần sư phụ và Thiên Vận Tông không phụ hắn thì hắn sẽ không phụ lại; một tòa Tế đàn bảy màu hạ xuống, lệnh bài khắc danh tự cháy hóa lửa tím bay về tế đàn. Sau đó được Thiên Vận Tử hỏi muốn chọn loại Cấm pháp thần thông nào."},{"chuong":"@c0474","importance":"normal","tieuDe":"Chọn Cấm pháp thần thông phòng thân","text":"Vương Lâm điểm lại sở học (Cấm pháp Đại Na Di, Ngân Long la bàn) và nhận ra chúng chỉ hữu dụng với tu sĩ Vấn Đỉnh, không đủ đối phó kẻ vượt Vấn Đỉnh hay đạt cảnh giới Toái Niết. Hắn xin Thiên Vận Tử truyền ‘Sinh tồn pháp thuật’ nhưng bị từ chối, nên được sư phụ điểm ánh sáng bảy màu đưa vào thế giới bảy màu để tự chọn theo cơ duyên."},{"chuong":"@c0474","importance":"normal","tieuDe":"Từ chối Sát Lục Tiên quyết","text":"Trong thế giới bảy màu, Vương Lâm phát hiện một Thiên Vận Tử áo xám dị thường (người ‘hơn một người’ — thứ 3601), mọi công kích đều xuyên qua như ảo ảnh. Qua sáu lần chạm mặt, người áo xám tiết lộ Thiên Vận Tử đưa hắn tới chính vì Sát Lục Tiên quyết, ra điều kiện ‘xuất thủ không lưu người sống’. Vương Lâm thi triển Sinh tử Luân hồi ý cảnh rồi trầm mặc từ chối: ‘Ta không học!’, sau đó nhận lấy ngọc giản người áo xám để lại."},{"chuong":"@c0476","importance":"normal","tieuDe":"Rời Thiên Vận Tinh tới Địa Tinh","text":"Vương Lâm dùng Truyền tống trận khổng lồ của Huyền Uyên Phái do Triệu Tứ kích hoạt, vượt liên tinh cầu rời Thiên Vận Tinh để tới Địa Tinh, mang theo lệnh bài khắc chữ “Thất” biểu thị thân phận Tử hệ Lão Thất."},{"chuong":"@c0476","importance":"normal","tieuDe":"Nhậm chức sứ giả Linh Nhạc quốc","text":"Tới Huyền Uyên Phái được Thiếu Tông Hứa Vân Sơn nghênh đón và kết giao; sau hai ngày, hắn được đưa tới Ngũ cấp tu chân quốc Linh Nhạc quốc để nhận chức sứ giả, ngầm tìm chỗ tĩnh tu tránh cạnh tranh ở Thiên Vận Tông."},{"bridge":true,"khoang":"@c0476–@c0476","text":"Trong hoa viên, Vương Lâm ngẫm về việc đề cao tu vi để đối phó mối uy hiếp Thác Lâm, nghiền ngẫm Sát lục tiên quyết, Sinh chi lạc ấn hộ thể và việc Thiên nghịch châu còn thiếu kim thuộc tính, nhớ tới Chu Tước Tinh xa xôi."},{"chuong":"@c0477","importance":"normal","tieuDe":"Nhậm Sứ giả Huyền Uyên Phái","text":"Vương Lâm chính thức nhậm chức Sứ giả của Huyền Uyên Phái tại Linh Nhạc quốc, được hơn trăm tu sĩ cung kính đón tiếp. Hứa Vân Sơn cáo từ rời đi, để mình hắn ở lại tọa trấn Thông Thiên tháp."},{"bridge":true,"khoang":"@c0477","text":"Hắn tuyên bố bế quan, cấm mọi người bước vào phạm vi ngàn dặm, dùng Cấm Phiên phóng hắc khí tạo màn sương đen và thả Chủ hồn từ Tôn Hồn Phiên ra phòng bị, rồi nghiên cứu Sát Lục Tiên quyết suốt hơn một tháng nhưng không tìm được điểm khởi đầu."},{"chuong":"@c0477","importance":"normal","tieuDe":"Áp chế Xạ Thần xa cắn trả","text":"Xạ Thần xa lần đầu cắn trả kể từ khi giải khai đạo phong ấn đầu tiên. Vương Lâm đã chuẩn bị trước, đại chiến với Khuất thú bên trong mấy ngày, dùng bí pháp áp chế khiến lần cắn trả thất bại."},{"chuong":"@c0477","importance":"normal","tieuDe":"Thu cấm chế, quyết đi Đông Hải","text":"Vương Lâm ngộ ra Sát Lục Tiên quyết phải cảm ngộ từ giết chóc thật, bèn thu hết màn sương đen ngàn dặm ngưng tụ thành khối cầu điện quang đen hóa Cấm Phiên tím đen, thu Chủ hồn vào Tôn Hồn Phiên tế luyện. Nhớ lời sư phụ dặn đến Đông Hải trong ba tháng (còn hơn một tháng), hắn lên đường, trước hết tới Ngũ Linh Sơn gặp Thiên Thai lão nhân."},{"chuong":"@c0478","importance":"normal","tieuDe":"Chọn Địa Ma Bắc Giới tu Sát Lục Tiên quyết","text":"Vương Lâm hỏi Thiên Thai lão nhân về nơi yêu thú tụ tập, nhận ngọc giản ghi ba chỗ rồi thuấn di tới Cực Bắc Địa Tinh, bước thẳng qua tấm bia Địa Ma Bắc Giới vào làn sương mù để tu luyện Sát Lục Tiên quyết — công pháp phải ở trong giết chóc mới lĩnh ngộ huyền diệu."},{"bridge":true,"khoang":"@c0478","text":"Hắn để tâm tới Đại La Kiếm Tông nhằm tìm tung tích Chu Dật tiền bối, đồng thời tò mò về Diệu Kim quả mà nhóm kiếm tu tranh chấp."},{"chuong":"@c0479","importance":"normal","tieuDe":"Nuôi Văn thú bằng yêu thú Hóa Thần","text":"Phi hành trong Tùng Mãng Sơn mạch tu luyện Sát Lục Tiên quyết, Vương Lâm giết tiểu thú sương đen và Bôn Ngưu thú (tương đương Hóa Thần kỳ), thu bụi khí nghi là sinh lực và thả Văn thú hấp thu nội đan, huyết nhục con mồi để thúc nó lớn lên."},{"chuong":"@c0479","importance":"normal","tieuDe":"Lần theo Đại La Kiếm Tông tìm Diệu Kim quả","text":"Vương Lâm dùng thần thức theo dõi đoàn Đại La Kiếm Tông, dự định dùng hai lão Anh Biến sơ kỳ làm thí luyện giả cho Sát Lục Tiên quyết, rồi cưỡi Văn thú bay nhanh về phía Nam nơi có Diệu Kim quả."},{"chuong":"@c0480","importance":"normal","tieuDe":"Bám theo đoàn Đại La Kiếm Tông","text":"Ngồi trên Văn thú vô thanh vô tức, Vương Lâm âm thầm đi theo đoàn Đại La Kiếm Tông tiến vào Địa Ma Bắc Giới tìm Diệu Kim quả. Dựa vào ký ức Cổ Thần Đồ Ti, hắn nhận ra Diệu Kim quả thực chất là kim linh căn mà các tu sĩ kiếm tông không biết cách dùng đúng — nuốt vào khiến thân thể cứng rắn, là thuốc bổ hi���m có với Cổ Thần thuở nhỏ. Hắn nhắm đoạt vật này cho Văn thú đang loé bạch mang khát vọng, vỗ đầu nó gật đầu cho phép."}],"tuViMoc":[{"chuong":"@c0459","canhGioi":"Anh Biến kỳ","text":"Đặt mục tiêu tu luyện đột phá tới Anh Biến trung kỳ để có đủ lực phá vỡ trận pháp khốn địa; chuyên tâm hấp thu tiên ngọc, tiên lực trong cơ thể đạt bão hòa dung nhập thân thể làm lực lượng dự phòng.","importance":"minor"},{"chuong":"@c0461","canhGioi":"Anh Biến trung kỳ","text":"Nhờ lượng lớn tiên ngọc trợ giúp đột phá khi còn bị vây trong thạch lâm, Vương Lâm tiến lên Anh Biến trung kỳ, uy lực Hóa Ma Chỉ nhờ đó tăng mấy lần.","importance":"minor"},{"chuong":"@c0462","canhGioi":"Anh Biến Trung Kỳ","text":"Khi tái xuất phá vây, Vương Lâm đã đột phá lên Anh Biến Trung Kỳ, khiến Triệu Tinh Sát kinh hãi vì hắn vừa thoát vây vừa tăng cảnh giới.","importance":"minor"},{"chuong":"@c0472","canhGioi":"Anh Biến trung kỳ","text":"Lĩnh ngộ Vấn Tâm chỉ cảnh tại Toái Tiên chi địa: khi tâm lạnh lẽo hơn cả vạn vật băng hàn, ý chí bất khuất vờn quanh thân, thần thức từ nguyên thần quét lui hàn khí xâm nhập kinh mạch. Đồng thời lĩnh ngộ Luân hồi đạo chính là đại Vô tình đạo, sau lưng hiện ra Luân hồi Hoạ trục chỉ hai màu đen trắng. Thuộc hệ tu tâm — không phải tu vi chính.","importance":"major"},{"chuong":"@c0473","canhGioi":"Anh Biến kỳ","importance":"major","text":"Ý cảnh nhập thể: trên nền hai mươi bước, Vương Lâm dung một tia cảm ngộ vào tâm cảnh, bước thêm năm bước đạt cực hạn hai mươi bảy bước, mở ra con đường lên Vấn Đỉnh. Sinh Tử Luân Hồi đạo của hắn là loại lĩnh ngộ cực hiếm khó thực chất hóa nhất; nhờ kết hợp Vấn Tâm chi đạo tại Toái Tiên chi địa mới khai thông. Bước thứ hai mươi tám nếu bước ra sẽ khiến tu vi sụp đổ, nguyên thần tiêu tan."}],"tuVi":"","nhanMach":[{"ten":"Trương Hướng Phàm","tag":"dong-minh","quanHe":"Đệ tử mở khóa trận pháp Phẩm Linh Các, cung kính dẫn Vương Lâm vào lấy tiên ngọc","ghiChu":"@c0458"},{"ten":"Tư Mã Như Phong","tag":"doi-thu","quanHe":"Đệ tử hàng thứ hai Lam tông, tham gia vây kích Vương Lâm","ghiChu":"@c0458"},{"ten":"Tứ sư tỷ (Tử hệ)","tag":"doi-thu","quanHe":"Đồng hệ Tử nhưng được người nhờ vả nên ra tay vây kích","ghiChu":"@c0458"},{"ten":"Người y phục xanh (như tượng băng)","tag":"doi-thu","quanHe":"Sư huynh ẩn mình nửa bước vấn đỉnh, coi Vương Lâm không xứng ra tay","ghiChu":"@c0458"},{"ten":"Thủy tổ đại nhân (Thiên Vận Tông)","tag":"su-mon","quanHe":"Thủy tổ tông môn, từng dặn chỉ cần không phạm môn quy thì khỏi quản Vương Lâm","ghiChu":"@c0458"},{"ten":"Tứ sư tỷ (Tử hệ)","tag":"su-mon","quanHe":"Sư tỷ đồng môn","ghiChu":"Trực tiếp na di Vương Lâm tới khốn địa, hẹn ba năm thả ra; từng hứa truyền thần thông na di cho hắn sau khi mọi chuyện giải quyết."},{"ten":"Đại sư huynh (Thiên Vận Tông)","tag":"doi-thu","quanHe":"Sư huynh đồng môn","ghiChu":"Người bố trí trận pháp thạch lâm vây khốn Vương Lâm."},{"ten":"Tào Nhất Đấu","tag":"dong-minh","quanHe":"Nguyên thần bị Vương Lâm thu nhận làm người dẫn đường","ghiChu":"Vương Lâm hứa cho một thân thể anh biến để đổi lấy việc dẫn đường về Thiên Vận Tông."},{"ten":"Triệu Tinh Sát","tag":"doi-thu","quanHe":"Đại sư huynh Tử hệ nhất mạch đứng sau việc na di vây khốn Vương Lâm","ghiChu":"Vương Lâm trở về quyết báo thù sự chèn ép của Triệu Tinh Sát và Tử hệ nhất mạch."},{"ten":"Hứa Lập Quốc","tag":"doi-thu","quanHe":"Kẻ thù bị Vương Lâm truy sát giữa thọ yến, đánh trọng thương nguyên thần","ghiChu":"Nhị sư huynh Tử hệ Thiên Vận Tông"},{"ten":"Triệu Tinh Sát","tag":"doi-thu","quanHe":"Cản Vương Lâm bằng Đại tự tại thiên địa quyết nhưng bị ma hỏa tự bạo phá vỡ","ghiChu":""},{"ten":"Bạch Vi","tag":"khac","quanHe":"Đệ tử Tử hệ, mỉm cười kỳ dị khi thấy Vương Lâm trở lại nhưng không ra tay","ghiChu":""},{"ten":"Triệu Tinh Sát","tag":"doi-thu","quanHe":"Đối thủ tranh danh hiệu Thiên Vận Thất Tử","ghiChu":"Bị Vương Lâm uy hiếp, đáp trả bằng thuật triệu Cổ Yêu nhưng bị phản phệ."},{"ten":"Xích Liệt","tag":"su-mon","quanHe":"Sư thúc trong Thiên Vận Tông","ghiChu":"Xuất hiện quát đuổi cổ yêu, vô tình cứu Hồn Thú của Vương Lâm."},{"ten":"Xích Liệt","tag":"su-mon","quanHe":"Tiền bối Thiên Vận Tông cùng tông, sư đệ của sư tôn","ghiChu":"Tiết lộ sư phụ kỳ vọng cao ở Vương Lâm và đại sư huynh sẽ không tranh danh hiệu Thiên Vận Thất Tử."},{"ten":"Tư Mã Như Phong","tag":"doi-thu","quanHe":"Đệ tử hàng thứ ba Lam Tông cùng Thiên Vận Tông","ghiChu":"Anh Biến đại viên mãn, gần Vấn Đỉnh; được Vương Lâm nhận ra trong lễ giảng đạo."},{"ten":"Tôn trưởng lão","tag":"khac","quanHe":"Cao thủ tu chân liên minh giáng lâm thọ yến","ghiChu":"Tiểu điêu ba mắt của Tôn trưởng lão đậu vai dò xét riêng Vương Lâm; hắn thấy quen quen."},{"ten":"Côn Bằng Tử","tag":"khac","quanHe":"Đầu lĩnh Hoàng Hệ cùng dự thọ yến","ghiChu":"Được Thiên Vận Tử tặng lại phi kiếm trung phẩm tiên khí."},{"ten":"Lăng Thiên Hầu","tag":"doi-thu","quanHe":"Kiếm Tôn Đại La Kiếm Tông","ghiChu":"Vương Lâm nhận ra thanh xà hình bảo kiếm của Lăng Thiên Hầu là Vũ chi đệ nhị kiếm bị hắn cướp ở Tiên giới năm xưa, gợi mở ân oán liên quan các thanh Vũ chi kiếm."},{"ten":"Triệu Hân Mộng","tag":"doi-thu","quanHe":"Tứ sư tỷ đồng môn","ghiChu":"Khiêu chiến Vương Lâm trong cuộc tranh phong hiệu; mô phỏng Hoá Ma chỉ của hắn để sáng chế Tử Ma thủ."},{"ten":"Vận Đường","tag":"khac","quanHe":"Đại sư huynh Hoàng hệ đồng môn","ghiChu":"Vương Lâm phát hiện biểu hiện quỷ dị: mắt Vận Đường co rút khi tinh thể vàng xuất hiện, ánh mắt thoáng sợ hãi rồi mỉm cười với hắn."},{"ten":"Trần Đào","tag":"doi-thu","quanHe":"Tử hệ Lão Lục giành phong hiệu","ghiChu":"Trần Đào khinh thường Vương Lâm, hai bên giao chiến tranh phong hiệu Thiên Vận Thất tử."},{"ten":"Triệu Hân Mộng","tag":"doi-thu","quanHe":"Tứ sư tỷ Tử hệ","ghiChu":"Gài bẫy hấp thu ma lực thất bại, thừa nhận xem thường Vương Lâm rồi bỏ cuộc."},{"ten":"Trần Đào","tag":"doi-thu","quanHe":"Đối thủ tại lễ chúc thọ","ghiChu":"Trần Đào tự xưng sư huynh, Vương Lâm phủ nhận tư cách đó của hắn; hai người giao chiến."},{"ten":"Lão già mặt đỏ","tag":"khac","quanHe":"Khách chúc thọ nhận ra sát chiêu","ghiChu":"Lão già mặt đỏ thấy Hoàng tuyền chỉ của Vương Lâm giống hệt sát chiêu của một “người điên” lão từng gặp."},{"ten":"Trần Đào","tag":"doi-thu","quanHe":"Sư huynh đệ Tử hệ kiêm đối thủ","ghiChu":"Thắng Vương Lâm đoạt phong hiệu Thiên Vận Thất tử, hẹn tái chiến sau khi Vương Lâm đạt Vấn Đỉnh."},{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư phụ","ghiChu":"Nhận Vương Lâm làm đệ tử chân chính, hứa truyền Cấm pháp thần thông và pháp bảo bản mạng, sắp đặt khảo nghiệm Toái Tiên chi địa."},{"ten":"Lăng Thiên Hầu","tag":"khac","quanHe":"Kiếm Tôn quen biết qua đại thọ","ghiChu":"Có ước hẹn với Thiên Vận Tử về Đông Hải Yêu Linh chi môn ba tháng sau."},{"ten":"Thiên Vận Tử áo xám","tag":"khac","quanHe":"Nhân vật bí ẩn ‘hơn một người’ trong thế giới bảy màu, nắm Sát Lục Tiên quyết, mời truyền nhưng Vương Lâm từ chối; vẫn để lại ngọc giản","ghiChu":"@c0474"},{"ten":"Hứa Vân Sơn","tag":"dong-minh","quanHe":"Thiếu Tông Huyền Uyên Phái chủ động ra đón và kết giao, đưa Vương Lâm tới Linh Nhạc quốc","ghiChu":"Cùng tu vi Anh Biến Trung kỳ"},{"ten":"Triệu Tứ","tag":"khac","quanHe":"Tu sĩ vận hành Truyền tống trận đưa Vương Lâm tới Địa Tinh, kính gọi hắn là Thất sư tổ"},{"ten":"Thiên Thai lão nhân","tag":"khac","quanHe":"Cao thủ đệ nhất Linh Nhạc quốc; từng đến Thông Thiên tháp thăm dò Vương Lâm rồi khiếp sợ, cuối chương Vương Lâm tìm đến tại Ngũ Linh Sơn","ghiChu":"@c0477"},{"ten":"Hứa Vân Sơn","tag":"dong-minh","quanHe":"Đưa Vương Lâm đến nhậm chức Sứ giả, gọi là Vương huynh, hẹn ngày sau cùng uống rượu","ghiChu":"@c0477"},{"ten":"Thiên Thai lão nhân","tag":"dong-minh","quanHe":"Tu sĩ Anh Biến kỳ phục vụ, trao ngọc giản ba chỗ yêu thú","ghiChu":"Gọi Vương Lâm là Sứ giả đại nhân"},{"ten":"Văn thú","tag":"khac","quanHe":"Vật nuôi","ghiChu":"Yêu thú đến từ tinh không, Vương Lâm nuôi lớn bằng cách thả hấp thu yêu thú Hóa Thần trở lên; đang ở thời khắc sắp tiến hóa."},{"ten":"Thiên Cầm cô nương","tag":"khac","quanHe":"Cùng hướng tới Diệu Kim quả","ghiChu":"Vương Lâm âm thầm theo dõi đoàn của nàng (bị Đại La Kiếm Tông ép dẫn đường)."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[{"ten":"Tiên ngọc","loai":"tài nguyên tu luyện","trangThai":"dang-co","moTa":"123.600 khối tiên ngọc lấy từ Phẩm Linh Các, dùng để hấp thu đột phá Anh Biến trung kỳ","nguon":"@c0458"}],"linhThao":[],"khac":[{"ten":"Lệnh bài Phẩm Linh Các","loai":"vật phẩm","trangThai":"da-dung","moTa":"Lệnh bài lấy tiên ngọc, ấn vào trận pháp ba đạo bạch ngân để mở cửa truyền tống lên tầng bảy và xác nhận thân phận lĩnh tiên ngọc","nguon":"@c0458"}]}},"nguon":["@c0458","@c0459","@c0460","@c0461","@c0462","@c0463","@c0464","@c0465","@c0466","@c0467","@c0468","@c0469","@c0470","@c0471","@c0472","@c0473","@c0474","@c0476","@c0477","@c0478","@c0479","@c0480"]},{"id":"truong-huong-pham","name":"Trương Hướng Phàm","gioiTinh":"nam","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0458","importance":"normal","tieuDe":"Mở khóa Phẩm Linh Các cho Thất sư tổ","text":"Trương Hướng Phàm ấn lệnh bài vào chỗ ba đạo bạch ngân giao nhau, kích hoạt trận pháp tạo cánh cửa truyền tống tại tầng thứ bảy Phẩm Linh Các, rồi cung kính mời Thất sư tổ Vương Lâm cầm lệnh bài tiến vào."}],"tuViMoc":[],"tuVi":"","nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Cung kính dẫn Thất sư tổ Vương Lâm vào Phẩm Linh Các lấy tiên ngọc","ghiChu":"@c0458"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0458"]},{"id":"trieu-tinh-sat","name":"Triệu Tinh Sát","gioiTinh":"nam","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0458","importance":"normal","tieuDe":"Góp mặt vây kích Vương Lâm","text":"Sắc mặt ôn hòa tiêu sái, Triệu Tinh Sát hiện ra từ gợn sóng bên cạnh Vương Lâm, là một trong năm người hợp vây tại Tử Lâm Các."},{"chuong":"@c0460","importance":"normal","tieuDe":"Độc thoại tranh đoạt thất tử","text":"Trong khi canh giữ tử vụ đại trận trước thọ yến, độc thoại điểm danh sáu vị tử còn lại (lão nhị bỏ cuộc, lão tam không để vào mắt, lão tứ nữ có cách giữ, lão ngũ bị phạt thiên ngục, lão lục xuất ngoại sinh tử chưa rõ), cảnh cáo lão thất chớ tranh đoạt với mình."},{"chuong":"@c0460","importance":"normal","tieuDe":"Nghênh đón Kim Ma tử","text":"Nhận ra Kim Ma tử trên chiến xa vàng, toát mồ hôi lạnh cung kính ra mắt rồi dẫn đường đưa chiến xa về Thiên Vận Tinh dự thọ yến."},{"chuong":"@c0461","importance":"normal","tieuDe":"Chủ tọa thọ yến Thiên Vận Tử","text":"Đại sư huynh Tử hệ nhất mạch ngồi chủ tọa tiệc thọ yến ngàn năm của sư tôn Thiên Vận Tử; vừa đứng dậy chúc rượu thì Vương Lâm — kẻ hắn từng mượn sức người ngoài na di vây khốn trong thạch lâm — xuất hiện thành cầu vồng tím từ chân trời đằng đông lao thẳng tới."},{"chuong":"@c0462","importance":"normal","tieuDe":"Cản Vương Lâm bất thành","text":"Sắc mặt cực xấu khi thấy Vương Lâm phá vây đạt Anh Biến Trung Kỳ, bóp nát chén rượu. Lão bước ra chắn trước nhị sư huynh, thi triển Đại tự tại thiên địa quyết tạo quầng sáng trắng bọc ma hỏa, nhưng bị ma hỏa tự bạo thiêu vỡ nên phải lui lại."},{"chuong":"@c0462","importance":"normal","tieuDe":"Đứng nhìn đồng môn bị giết","text":"Sau khi cản thất bại, Triệu Tinh Sát đứng nhìn Hứa Lập Quốc bị Vương Lâm truy sát mà cười lạnh, không hề ra tay cứu, hé lộ rạn nứt và toan tính trong nội bộ Tử hệ."},{"chuong":"@c0463","importance":"normal","tieuDe":"Triệu Cổ Yêu cấm thuật","text":"Bị Vương Lâm dồn ép và bị lão tứ từ chối trợ giúp, Triệu Tinh Sát dùng trước thuật triệu Cổ Yêu vốn định để dành cho dịp tranh danh hiệu Thiên Vận Thất Tử. Ký hiệu cổ quái lóe giữa lông mày gọi ra hư ảnh yêu vật trăm trượng, nhưng càng dùng thân thể hắn càng suy yếu."},{"chuong":"@c0463","importance":"normal","tieuDe":"Phản phệ và tham kiến Xích Liệt","text":"Cổ yêu bị tiếng hét của Xích Liệt buộc rút lui, Triệu Tinh Sát phun máu, cười u ám nhìn Vương Lâm. Hắn cung kính tham kiến Xích Liệt sư thúc, xác nhận mấy ngàn năm trước khi mới bái nhập Thiên Vận Tông từng gặp mặt một lần."},{"chuong":"@c0464","importance":"normal","tieuDe":"Bị Xích Liệt áp giải","text":"Sau khi gượng dùng yêu linh chưa kịp luyện hóa, Triệu Sát Tinh bị Xích Liệt túm mang đi để sư phụ trừng phạt, mất chức chủ yến hội về tay Vương Lâm."}],"tuViMoc":[],"tuVi":"","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Tham gia nhóm năm người vây kích Vương Lâm","ghiChu":"@c0458"},{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"sư tôn","ghiChu":"Triệu Tinh Sát là đại sư huynh Tử hệ thuộc Thiên Vận Thất tử của Thiên Vận Tử."},{"ten":"Kim Ma tử","tag":"khac","quanHe":"khách chúc thọ","ghiChu":"Cung kính nghênh đón, dẫn đường về Thiên Vận Tinh."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"đối thủ ngầm (nghi là lão thất)","ghiChu":"Triệu Tinh Sát cảnh cáo lão thất, đối tượng có thể chính là Vương Lâm."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Sư đệ bị hắn chèn ép, na di vây khốn","ghiChu":"Vương Lâm trở về quyết báo thù giữa thọ yến."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối đầu, cản bất thành rồi bị ma hỏa đánh lui","ghiChu":""},{"ten":"Hứa Lập Quốc","tag":"khac","quanHe":"Đồng môn Tử hệ mà Triệu Tinh Sát bỏ mặc không cứu","ghiChu":""},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ, bị hắn tố giết lão nhị","ghiChu":"Định dùng Cổ Yêu trừ Vương Lâm nhưng thất bại."},{"ten":"Tứ sư tỷ (Tử hệ)","tag":"khac","quanHe":"Cầu viện trợ nhưng bị từ chối","ghiChu":"Lão tứ viện cớ đã đền ân ba tháng trước và không tranh danh hiệu."},{"ten":"Xích Liệt","tag":"su-mon","quanHe":"Sư thúc Thiên Vận Tông","ghiChu":"Tham kiến cung kính, từng gặp mấy ngàn năm trước."},{"ten":"Xích Liệt","tag":"su-mon","quanHe":"Tiền bối tông môn áp giải","ghiChu":"Bị Xích Liệt túm đi sau khi gượng dùng yêu linh."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0458","@c0460","@c0461","@c0462","@c0463","@c0464"],"aliases":["Triệu Sát Tinh"]},{"id":"tu-ma-nhu-phong","name":"Tư Mã Như Phong","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Lam tông (Thiên Vận Tông)","trangThai":"gan-bo"},{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến kỳ","trangThai":"song","blurb":"Đệ tử đứng hàng thứ hai thuộc Lam tông của Thiên Vận Tông, y phục lam thêu ba con lam long, tươi cười ôn hòa nhưng tham gia vây kích Vương Lâm.","vaiTro":"Đệ tử Lam tông Thiên Vận Tông, một trong năm người vây kích Vương Lâm","tinhCach":[{"text":"Tươi cười ôn hòa nhưng ngầm hiểm, khéo quan sát đối thủ","chuong":"@c0458"}],"tabs":{"diem":[{"text":"Y phục lam thêu ba con lam long, đứng hàng thứ hai trong đệ tử Lam tông","chuong":"@c0458"}],"kinhLich":[{"chuong":"@c0458","importance":"normal","tieuDe":"Vây kích và giới thiệu sư huynh ẩn mình","text":"Tư Mã Như Phong tươi cười hiện thân trong nhóm vây kích Vương Lâm tại Tử Lâm Các, đoán Vương Lâm đã Anh Biến hậu kỳ đại viên mãn, rồi giới thiệu một vị sư huynh ẩn mình mạnh hơn hẳn."}],"tuViMoc":[],"tuVi":"Đệ tử Anh Biến kỳ đứng hàng thứ hai thuộc Lam tông Thiên Vận Tông.","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Tham gia vây kích, đoán định tu vi Vương Lâm","ghiChu":"@c0458"},{"ten":"Người y phục xanh (như tượng băng)","tag":"dong-minh","quanHe":"Giới thiệu vị sư huynh ẩn mình nửa bước vấn đỉnh","ghiChu":"@c0458"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0458"]},{"id":"tu-su-ty-tu-he","name":"Tứ sư tỷ (Tử hệ)","cn":"","aliases":["Tứ sư tỷ","Tứ sư tỷ (Tử hệ)"],"gioiTinh":"nu","theLuc":[{"ten":"Tử hệ (Thiên Vận Tông)","trangThai":"gan-bo"},{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến hậu kỳ","trangThai":"song","blurb":"Nữ tử Anh Biến hậu kỳ thuộc Tử hệ Thiên Vận Tông; được người nhờ vả nên ra tay, thi triển Tử thuật - Na di trong cuộc vây kích Vương Lâm.","vaiTro":"Sư tỷ đồng hệ Tử của Vương Lâm, một trong năm người vây kích","tinhCach":[{"text":"Bất đắc dĩ ra tay vì chịu lời nhờ vả của người khác","chuong":"@c0458"}],"tabs":{"diem":[{"text":"Anh Biến hậu kỳ, thuộc Tử hệ và sử dụng Tử thuật","chuong":"@c0458"}],"kinhLich":[{"chuong":"@c0458","importance":"normal","tieuDe":"Thi triển Tử thuật - Na di khởi chiến","text":"Bất đắc dĩ thừa nhận được người nhờ vả, tứ sư tỷ bắt quyết điểm vào hư không, một tia sáng bạc lan ra bao trùm mười dặm, mở màn cuộc vây kích Vương Lâm tại Tử Lâm Các."},{"chuong":"@c0459","importance":"normal","tieuDe":"Na di vây khốn lão thất","text":"Tứ sư tỷ — nữ tử xinh đẹp như tiên tử đội mũ tơ tằm — dùng thần thông na di đưa Vương Lâm tới thạch lâm khốn địa, hứa sau ba năm sẽ tới thả ra và truyền thần thông na di cho hắn khi mọi chuyện giải quyết xong. Trước khi rời đi, nàng nói với đại sư huynh rằng nhân tình năm đó nay đã hồi báo, từ nay hai người không còn liên quan, rồi hóa ngân quang bay về Thiên Vận Tông."},{"chuong":"@c0463","importance":"normal","tieuDe":"Từ chối ra tay giúp Triệu Tinh Sát","text":"Khi Triệu Tinh Sát lớn tiếng cầu viện, lão tứ bình thản đáp ân tình ba tháng trước đã đền đáp và đã đồng ý không tranh đoạt danh hiệu Thiên Vận Thất Tử với hắn, đòi một lý do mới chịu ra tay. Triệu Tinh Sát cắn răng tức giận mất chỗ dựa."},{"chuong":"@c0464","importance":"normal","tieuDe":"Trao ngọc giản hai cấm pháp","text":"Đêm khuya yến tàn, tứ sư tỷ đưa Vương Lâm một ngọc giản chứa cấm pháp đại na di cùng một cấm pháp do sư tôn phỏng theo hạ phẩm tiên thuật sáng tạo, coi như xin lỗi việc tháng trước — lúc đó nàng dùng cấm pháp phong ấn nhưng chưa thực sự ra tay."},{"bridge":true,"khoang":"@c0465","text":"Trong thọ yến, Tứ sư tỷ truyền âm than thở với Vương Lâm rằng Tử Tông đang sa sút vì tranh đoạt nội bộ quá nhiều, danh hiệu Thiên Vận Thất Tử thay đổi thường xuyên, không còn uy phong như thời Tôn Vân sư đệ năm xưa."},{"bridge":true,"khoang":"@c0468","text":"Tứ sư tỷ thần thái như thường, bình tĩnh trụ vững khảo nghiệm áp lực cùng Vương Lâm; khi thấy hắn vượt trội nàng liếc một cái đầy thâm ý nhưng không nói gì."},{"chuong":"@c0469","importance":"normal","tieuDe":"Khiêu chiến Vương Lâm tranh phong hiệu","text":"Sau khi Bạch Vi bỏ cuộc, Triệu Hân Mộng nhíu mắt nhìn Vương Lâm, đòi giao chiến một trận để hắn không đạt phong hiệu quá đơn giản. Khi khai chiến nàng giật lui hơn mười trượng, vận Tử Ma thủ — thần thông tự sáng chế bằng cách mô phỏng Hoá Ma chỉ của Vương Lâm — đẩy tử quang gào rít lao tới."},{"chuong":"@c0470","importance":"normal","tieuDe":"Bẫy hấp thu ma lực bất thành","text":"Triệu Hân Mộng bắt chước Tử Ma thủ dụ Vương Lâm dùng Hoá Ma chỉ để cướp ma lực, định không tranh phong hiệu Thiên Vận Thất tử với hắn. Nàng dùng hạt châu trắng hút ma lực khiến nó hoá đen, nhưng Vương Lâm khiến ma lực hư ảo tự sụp, hạt châu vỡ vụn; nàng đe doạ nhưng bị từ chối."},{"chuong":"@c0470","importance":"normal","tieuDe":"Đấu Cửu chuyển luyện tiên rồi bỏ cuộc","text":"Nàng thi Cửu chuyển luyện tiên quyết tu ra kim sắc lốc xoáy năm vòng, nhưng kinh ngạc khi Vương Lâm chỉ vài ngày đã đạt ngũ chuyển lại rút chiến phủ và Xạ Thần xa. Triệu Hân Mộng thừa nhận đã xem thường hắn rồi rời đi, sau đó truyền âm cho Trần Đào về việc Tôn Vân."}],"tuViMoc":[],"tuVi":"Nữ tử Anh Biến hậu kỳ thuộc Tử hệ Thiên Vận Tông.","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đồng hệ Tử nhưng ra tay vây kích theo lời nhờ vả","ghiChu":"@c0458"},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Sư đệ đồng môn (lão thất)","ghiChu":"Đích thân na di đưa hắn tới khốn địa, hẹn ba năm thả; hứa truyền thần thông na di."},{"ten":"Đại sư huynh (Thiên Vận Tông)","tag":"doi-thu","quanHe":"Sư huynh đồng môn, từng có nhân tình","ghiChu":"Tuyên bố nhân tình năm xưa đã hồi báo, cắt đứt quan hệ với đại sư huynh."},{"ten":"Triệu Tinh Sát","tag":"khac","quanHe":"Người từng chịu ân, nay cầu viện","ghiChu":"Lão tứ từ chối trợ giúp."},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Sư đệ cùng Tử hệ","ghiChu":"Trao ngọc giản hai cấm pháp xin lỗi việc tháng trước."},{"ten":"Tôn Vân","tag":"su-mon","quanHe":"Sư đệ Tử Hệ thời còn uy phong, được nhắc lại khi than về sự sa sút","ghiChu":""},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Đồng môn Tử hệ","ghiChu":"Hai người duy nhất của Tử hệ trụ vững khảo nghiệm; Tứ sư tỷ liếc Vương Lâm đầy thâm ý trước biểu hiện vượt trội của hắn."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Lão Thất đồng môn","ghiChu":"Khiêu chiến và giao chiến với Vương Lâm; mô phỏng Hoá Ma chỉ của hắn thành Tử Ma thủ."},{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư phụ"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Thất sư đệ Tử hệ (giả danh)","ghiChu":"Gài bẫy hấp thu ma lực bất thành, đánh giá thấp rồi bỏ cuộc."},{"ten":"Trần Đào","tag":"su-mon","quanHe":"Đồng môn Tử hệ","ghiChu":"Truyền âm cho Trần Đào về việc Tôn Vân khiến hắn biến sắc."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Tử thuật - Na di","moTa":"Pháp thuật Tử hệ, bắt quyết điểm vào hư không phát tia sáng bạc bao trùm mười dặm","nguon":"@c0458"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0458","@c0459","@c0463","@c0464","@c0465","@c0468","@c0469","@c0470"]},{"id":"nguoi-y-phuc-xanh-tuong-bang","name":"Người y phục xanh (như tượng băng)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Nửa bước vấn đỉnh kỳ","trangThai":"song","blurb":"Vị sư huynh ẩn mình do Tư Mã Như Phong giới thiệu; lạnh lùng như chúa tể thiên hạ, tu vi đã bước nửa bước vào vấn đỉnh kỳ.","vaiTro":"Cường giả ẩn mình trong nhóm vây kích Vương Lâm","tinhCach":[{"text":"Lạnh lùng kiêu ngạo, đứng như tượng băng ngàn năm, coi đối thủ không xứng để ra tay","chuong":"@c0458"}],"tabs":{"diem":[{"text":"Tu vi nửa bước vấn đỉnh kỳ, ánh mắt đầy vẻ chúa tể thiên hạ","chuong":"@c0458"}],"kinhLich":[{"chuong":"@c0458","importance":"normal","tieuDe":"Lộ diện trong cuộc vây kích","text":"Một tiếng nói lạnh như băng vang lên, người y phục xanh xuất hiện sau lưng Vương Lâm vài chục trượng, đứng như tượng băng ngàn năm, liếc một cái rồi nhắm mắt dưỡng thần vì coi Vương Lâm không xứng để ra tay."}],"tuViMoc":[],"tuVi":"Tu vi đã bước nửa bước vào vấn đỉnh kỳ.","nhanMach":[{"ten":"Tư Mã Như Phong","tag":"dong-minh","quanHe":"Được Tư Mã Như Phong giới thiệu là sư huynh ẩn mình","ghiChu":"@c0458"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Tham gia vây kích nhưng coi Vương Lâm không xứng để ra tay","ghiChu":"@c0458"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0458"]},{"id":"thuy-to-thien-van-tong","name":"Thủy tổ đại nhân (Thiên Vận Tông)","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Thủy tổ của Thiên Vận Tông; từng dặn chỉ cần Vương Lâm không phạm môn quy thì khỏi quản, và cạnh tranh nội bộ giữa đệ tử của ông cực kỳ khốc liệt.","vaiTro":"Thủy tổ tông môn Thiên Vận Tông, được nhắc tên","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c0458","importance":"normal","tieuDe":"Lệnh không quản Vương Lâm","text":"Được ba chấp pháp trưởng lão nhắc tới: Thủy tổ từng dặn chỉ cần Vương Lâm không phạm môn quy thì khỏi quản; cạnh tranh nội bộ giữa các đệ tử của ông cực kỳ khốc liệt."}],"tuViMoc":[],"tuVi":"","nhanMach":[{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Thủy tổ tông môn, ra lệnh không quản chừng nào Vương Lâm chưa phạm môn quy","ghiChu":"@c0458"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0458"]},{"id":"dai-su-huynh-thien-van-tong","name":"Đại sư huynh (Thiên Vận Tông)","gioiTinh":"nam","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0459","importance":"normal","tieuDe":"Bố trí trận pháp vây khốn","text":"Đại sư huynh là người bố trí trận pháp tại thạch lâm khốn địa để vây Vương Lâm — màn sáng bạc bao phủ mười dặm, triệt tiêu mọi kiếm quang pháp bảo phóng ra. Bị tứ sư tỷ tuyên bố cắt đứt nhân tình năm xưa khi nàng đưa Vương Lâm tới đây."}],"tuViMoc":[],"nhanMach":[{"ten":"Tứ sư tỷ (Tử hệ)","tag":"doi-thu","quanHe":"Sư muội đồng môn, từng có nhân tình","ghiChu":"Bị tứ sư tỷ tuyên bố nhân tình đã hồi báo, từ nay không còn liên quan."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Sư đệ đồng môn","ghiChu":"Bố trí trận pháp vây khốn Vương Lâm tại thạch lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0459"]},{"id":"hua-lap-quoc","name":"Hứa Lập Quốc","gioiTinh":"nam","tabs":{"diem":[],"kinhLich":[{"bridge":true,"khoang":"@c0459–@c0459","text":"Là khí linh trong tiên kiếm của Vương Lâm, được điều khiển cùng loan đao lao thử phá trận pháp khốn địa nhưng thất bại, kêu thảm rằng không phá nổi thứ này rồi bị thu về."},{"chuong":"@c0462","importance":"normal","tieuDe":"Nghênh chiến rồi bị trọng thương","text":"Là nhị sư huynh Tử hệ Thiên Vận Tông, hóa tử quang nghênh chiến Vương Lâm, phóng Thượng chi lực hóa đám cát như bầy ong nhưng bị Cấm Phiên xé tan. Hắn dùng cấm thuật Tiên Ma thể hóa toàn thân thành sương mù đen để trốn, viện cớ hôm nay là đại thọ sư tôn, song bị tiên kiếm cùng loan đao chém tan, cuối cùng nguyên thần bị Côn Cực Tiên đánh trúng, trọng thương sắp tan."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"cap-tren","quanHe":"Chủ tử","ghiChu":"Gọi Vương Lâm là Chủ tử, được sai phá vây bất thành."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm truy sát, đả thương nguyên thần giữa thọ yến","ghiChu":""},{"ten":"Triệu Tinh Sát","tag":"khac","quanHe":"Đồng môn Tử hệ đứng nhìn không cứu khi hắn bị giết","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0459","@c0462"],"aliases":["Lão nhị","Nhị sư huynh"]},{"id":"kim-ma-tu","name":"Kim Ma tử","gioiTinh":"nam","tabs":{"diem":[{"text":"Tôn giả độc chiếm một tiểu tinh, hoành hành ngang ngược, tính nóng nảy, giết người vô số.","chuong":"@c0460"},{"text":"Thân to như quả cầu thịt, da trong suốt như thủy tinh.","chuong":"@c0460"}],"kinhLich":[{"chuong":"@c0460","importance":"normal","tieuDe":"Tới chúc thọ Thiên Vận Tử","text":"Đáp chiến xa vàng cao hơn ngàn trượng do bốn yêu thú khổng lồ nâng đỡ, kèm mười tùy tùng trường sam bạc, tới Thiên Vận Tinh dự thọ yến; được Triệu Tinh Sát cung kính dẫn đường, thân phận chỉ đủ ngồi ở thọ tiệc do Xích tông tổ chức."}],"tuViMoc":[{"chuong":"@c0460","canhGioi":"Thông thiên (đồn đạt Hư Thật nhị ý)","text":"Tu vi loại thông thiên, có lời đồn đã chạm tới cảnh giới truyền thuyết Hư Thật nhị ý.","importance":"major"}],"nhanMach":[{"ten":"Thiên Vận Tử","tag":"khac","quanHe":"khách chúc thọ","ghiChu":"Tự thân tới chúc đại thọ ngàn năm."},{"ten":"Triệu Tinh Sát","tag":"khac","quanHe":"người nghênh đón","ghiChu":"Được dẫn đường về Thiên Vận Tinh."}],"tuiDo":{"phapBao":[{"ten":"Chiến xa màu vàng của Kim Ma tử","trangThai":"dang-co","moTa":"Chiến xa khổng lồ cao hơn ngàn trượng đầy mũi nhọn, bốn yêu thú nâng đỡ; trên xe có ghế lớn và mười tùy tùng.","nguon":"@c0460"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"theLuc":[{"ten":"Thiên Vận Tông","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"Thông thiên","trangThai":"song","vaiTro":"Tôn giả độc chiếm một tiểu tinh thuộc Thiên Vận Tông, khách chúc thọ Thiên Vận Tử.","blurb":"Tôn giả thân tròn như cầu thịt da trong như thủy tinh, hoành hành ngang ngược, tu vi thông thiên đồn đạt Hư Thật nhị ý.","nguon":["@c0460"]},{"id":"tao-nhat-dau","name":"Tào Nhất Đấu","gioiTinh":"nam","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0461","importance":"normal","tieuDe":"Dẫn đường về Thiên Vận Tông","text":"Được Vương Lâm phất hồn phiên thả nguyên thần ra, Tào Nhất Đấu nhận ra đây chính là Thiên Vận Tinh quê cũ, chỉ về hướng tây cách khoảng ba mươi vạn dặm là sơn môn Thiên Vận Tông; hắn tình nguyện dẫn đường vì được hứa cho một thân thể anh biến."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Người thu nhận nguyên thần của hắn ở Thi Âm tông","ghiChu":"Làm người dẫn đường để đổi lấy lời hứa một thân thể anh biến."}],"tuiDo":{}},"nguon":["@c0461"]},{"id":"thien-van-tu-su-ton","name":"Thiên Vận Tử","cn":"","aliases":["Sư tôn Tử tông"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Sư tôn của Tử tông trong Thiên Vận Tông, được tông môn mở thọ yến ngàn năm và sẽ giảng đạo sau bảy ngày.","vaiTro":"Sư tôn của Tử hệ nhất mạch, nhân vật cấp cao trên Thiên Vận Tinh.","tinhCach":[],"tabs":{"diem":[{"text":"Bậc sư tôn được cả Tử tông tổ chức thọ yến ngàn năm","chuong":"@c0461"}],"kinhLich":[{"chuong":"@c0461","importance":"normal","tieuDe":"Thọ yến ngàn năm","text":"Thiên Vận Tông mở thọ yến ngàn năm mừng sư tôn Thiên Vận Tử, bày tiệc tiên quả sơn tửu náo nhiệt; bảy ngày thọ yến xong sẽ là ngày Thiên Vận Tử giảng đạo, một tháng sau là kỳ Tử Hoàng nhị tông tranh đoạt danh hiệu Thiên Vận Thất tử."},{"chuong":"@c0465","importance":"normal","tieuDe":"Chủ trì đại thọ vạn năm, giảng Thiên Vận Chi Đạo","text":"Thiên Vận Tử xuất hiện trên quầng sáng bảy màu, được đệ tử đích hệ bảy tông và vô số tu sĩ tham bái. Ông mời lão bằng hữu Tôn trưởng lão từ tu chân liên minh xuất hiện, nhận phi kiếm trung phẩm tiên khí rồi tặng lại Côn Bằng Tử, sau đó khoanh chân ngồi giảng Thiên Vận Chi Đạo với cốt lõi ‘nghe theo mệnh trời’."},{"chuong":"@c0466","importance":"normal","tieuDe":"Giảng ba bước tu đạo","text":"Ngồi khoanh chân trên tường vân, Thiên Vận Tử giảng đạo cho đệ tử lục hệ và tu sĩ bốn phía: liệt kê bảy cảnh Ngưng Khí tới Vấn Đỉnh thuộc chữ ‘tu’ (bước một), bước hai là hư thực nhị ý và toái niết tam cảnh nơi hầu hết tu sĩ phải dừng chân, bước ba là chữ ‘đạo’ cầu thiên vận. Hắn phân biệt tu tiên, tu chân, tu đạo và thừa nhận chính mình bước một còn chưa hoàn thành."},{"chuong":"@c0466","importance":"normal","tieuDe":"Tiết lộ về ‘hắn’","text":"Đáp lời hoài nghi của Vương Lâm, Thiên Vận Tử than nhẹ lộ vẻ bồi hồi hiếm thấy, kể rằng ba ngàn năm trước hắn cũng không tin có bước thứ ba cho tới khi gặp được ‘hắn’ — một nhân vật bí ẩn cực mạnh."},{"chuong":"@c0467","importance":"normal","tieuDe":"Thi triển trung phẩm Dẫn Tiên thuật","text":"Kết thúc ba ngày giảng đạo nhân đại thọ vạn năm, trước truy hỏi của tu sĩ, Thiên Vận Tử tiết lộ về “hắn” — kẻ duy nhất lão biết đã đạt tới bước thứ ba và từng khiến Tu Chân Liên Minh nếm khổ một lần. Sau đó lão tuyên bố thi triển một trung phẩm Tiên thuật tên Dẫn Tiên thuật, lấy Lăng Thiên Hầu làm đối tượng, phóng xích mang lên trời hiện mảnh màu đỏ mây cuộn như rồng kèm thiên uy giáng xuống."},{"chuong":"@c0468","importance":"normal","tieuDe":"Thi triển Dẫn Tiên thuật cuốn đệ tử Đại La Kiếm Tông","text":"Trong đại thọ vạn năm tuổi, Thiên Vận Tử thi triển Dẫn Tiên thuật (Trung phẩm Tiên thuật), hô “Dẫn độ” cuốn hơn vạn đệ tử Đại La Kiếm Tông mê man bay lên hư không, triệu hư ảnh sứ giả Tiên giới ấn chưởng phong kín; làm nhục Kiếm Tôn Lăng Thiên Hầu và hứa ba ngày sau trả người."},{"chuong":"@c0468","importance":"normal","tieuDe":"Tuyên bố tranh đoạt phong hiệu Thiên Vận Thất tử","text":"Lão công bố trong bảy hệ đệ tử chỉ Hoàng hệ và Tử hệ chưa ai nắm phong hiệu Thiên Vận Thất tử, hôm nay sẽ xuất hiện người mang phong hiệu từ hai hệ này; nh��c lại lão Tam Hoàng hệ từng đạt phong hiệu rồi mất tích ở tinh không ba mươi năm trước."},{"chuong":"@c0469","importance":"normal","tieuDe":"Phân phong hiệu, khuyên Vương Lâm tranh đoạt","text":"Thiên Vận Tử chủ trì phân phong hiệu Thiên Vận Thất tử, trao tinh thể vàng cho Côn Bằng Tử của Hoàng hệ và nhấn mạnh phong hiệu là dấu hiệu thân phận của Thiên Vận Tông. Khi Vương Lâm định bỏ cuộc, lão ngẩn ra rồi đích thân khuyên giải, cho nửa nén hương suy xét, dặn đừng để người ngoài mê hoặc; lão liếc Vận Đường bằng ánh mắt âm trầm khiến lão này run sợ."},{"chuong":"@c0469","importance":"normal","tieuDe":"Độc thoại về bước thứ ba Thiên Vận đạo","text":"Lão hé lộ ba vạn năm trước từng gặp ‘hắn’, người để lại lời rằng chỉ khi tìm được kẻ phù hợp số phận mới tiến được bước thứ ba của Thiên Vận đạo. Suốt ba vạn năm lão thất bại vô số lần, tổn thất hơn nửa đệ tử, nay chăm chú nhìn ngón trỏ Vương Lâm để xét hắn có phải người đó, ánh mắt cuối cùng lộ một tia chán nản."},{"chuong":"@c0470","importance":"normal","tieuDe":"Phán định tranh phong hiệu","text":"Sắp đại thọ vạn năm, Thiên Vận Tử nhận đoá Thất thải lưu ly quang từ Trần Đào, phán chỉ Trần Đào và Vương Lâm đủ tư cách tranh phong hiệu Thiên Vận Thất tử nhưng chỉ một người đạt; hắn tán thưởng cả hai trong trận giao đấu."},{"chuong":"@c0472","importance":"normal","tieuDe":"Kết thúc đại thọ, thu nhận Vương Lâm","text":"Tuyên Trần Đào thắng và trao phong hiệu Thiên Vận Thất tử của Tử hệ; kết thúc đại thọ vạn năm tuổi khiến tu sĩ tản đi. Nhận Vương Lâm làm đệ tử chân chính, đưa về Tổng tông ba ngọn núi tại Thiên Vận Tinh, khảo Vương Lâm câu đố Chân huyễn pháp rồi sắp đặt khảo nghiệm leo Toái Tiên chi địa."},{"chuong":"@c0473","importance":"major","tieuDe":"Thu Vương Lâm làm đệ tử Tử hệ","text":"Thiên Vận Tử triệu Vương Lâm lên đỉnh, kể nguồn gốc Thiên Vận Tông: tổ tiên không phải tu sĩ mà là Thiên vận số, cả đời theo đuổi Thiên vận, tin hết thảy vận số là trời định. Lão vốn không định tới Chu Tước Tinh, vừa lúc gặp Vương Lâm đang cảm ngộ Hóa Thần tìm bản nguyên thiên đạo nên vì quý tài và vận số thầy trò mà thu làm đệ tử thứ bảy của Tử hệ. Lão xé không trung tỏa ánh sáng bảy màu Tối hỉ thất thải chiếu rọi gần nửa bầu trời Thiên Vận Tinh, rồi hỏi Vương Lâm chọn loại Cấm pháp thần thông nào."},{"chuong":"@c0474","importance":"normal","tieuDe":"Mở 3600 Cấm pháp thần thông cho đệ tử","text":"Thiên Vận Tử bình tĩnh để Vương Lâm tự chọn thần thông, từ chối yêu cầu ‘Sinh tồn pháp thuật’ (vi sư không có), rồi nâng tay phải điểm ánh sáng bảy màu, mở ra thế giới bảy màu chứa 3600 đạo Cấm pháp thần thông để đệ tử chọn theo cơ duyên. Lão sở hữu thần thông bảy màu (Tối hỷ khẩu thất thải) và từng có hứa hẹn với Thiên Vận Tử áo xám."}],"tuViMoc":[],"nhanMach":[{"ten":"Tôn trưởng lão","tag":"ban-be","quanHe":"Lão bằng hữu từ tu chân liên minh, được mời dự đại thọ","ghiChu":"Xưng hô thân mật, gọi nhau là lão quái."},{"ten":"Côn Bằng Tử","tag":"su-mon","quanHe":"Đệ tử đầu lĩnh Hoàng Hệ, được tặng phi kiếm tiên khí","ghiChu":""},{"ten":"Hắc y nhân (mặt sẹo)","tag":"khac","quanHe":"Tu sĩ hắc y mặt sẹo trầm giọng hỏi hắn về bước thứ ba của tu đạo giữa buổi giảng.","ghiChu":""},{"ten":"Lăng Thiên Hầu","tag":"doi-thu","quanHe":"khách dự đại thọ kiêm đối tượng thi triển Tiên thuật","ghiChu":"Hai cao thủ đối thoại trêu chọc nhau; Lăng Thiên Hầu lạnh lùng đồng ý làm đối tượng để Thiên Vận Tử biểu diễn Dẫn Tiên thuật."},{"ten":"Lăng Thiên Hầu","tag":"doi-thu","quanHe":"Khách dự thọ bị làm nhục","ghiChu":"Thiên Vận Tử ra tay với đệ tử Đại La Kiếm Tông của Lăng Thiên Hầu, khiến lão âm trầm trách móc nhưng đành nhẫn nhịn chờ ba ngày."},{"ten":"Vận Đường","tag":"su-mon","quanHe":"Đệ tử lão đại Hoàng hệ","ghiChu":"Thiên Vận Tử nhìn Vận Đường bằng ánh mắt thâm thuý rồi âm trầm khi lão nhường phong hiệu và lộ biểu hiện quỷ dị."},{"ten":"Trần Đào","tag":"su-mon","quanHe":"Đệ tử lâu năm","ghiChu":"Nhận kỳ bảo Trần Đào dâng, cho hắn tranh phong hiệu."},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Đệ tử chân chính mới thu nhận","ghiChu":"Hứa truyền Cấm pháp thần thông và pháp bảo bản mạng, cho đặc ân tự chọn."},{"ten":"Trần Đào","tag":"su-mon","quanHe":"Đệ tử Tử hệ","ghiChu":"Trao phong hiệu Thiên Vận Thất tử."},{"ten":"Lăng Thiên Hầu","tag":"khac","quanHe":"Kiếm Tôn có ước hẹn","ghiChu":"Ba tháng sau phải tuyển người tiến vào Đông Hải Yêu Linh chi môn."},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Đệ tử thứ bảy của Tử hệ","ghiChu":"Thu nhận sau khi Vương Lâm đạt ý cảnh nhập thể hai mươi bảy bước."},{"ten":"Thiên Vận Tử áo xám","tag":"khac","quanHe":"Có hứa hẹn từ trước; nhờ đó người áo xám mới truyền Sát Lục Tiên quyết cho đệ tử của Thiên Vận Tử","ghiChu":"@c0474"}],"tuiDo":{}},"nguon":["@c0461","@c0465","@c0466","@c0467","@c0468","@c0469","@c0470","@c0472","@c0473","@c0474"]},{"id":"bach-vi","name":"Bạch Vi","cn":"","gioiTinh":"nam","trangThai":"song","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0462","importance":"normal","tieuDe":"Thái độ khó lường giữa yến tiệc","text":"Khi Vương Lâm phá vây xông vào thọ yến, mắt Bạch Vi lộ tia kỳ dị, chỉ mỉm cười khó hiểu mà ung dung uống rượu, không hề ra tay, gợi ý còn ẩn tình giữa các đệ tử Tử hệ."},{"chuong":"@c0464","importance":"normal","tieuDe":"Lộ tâm tư báo thù đại sư huynh","text":"Trên đường về Tử Vi Các, Bạch Vi lộ vẻ ác độc, lẩm bẩm trách sư tôn bất công đã cấy yêu linh vào thân đại sư huynh — nếu yêu linh thức tỉnh, đại sư huynh khôi phục bản lãnh thì hắn vĩnh viễn không báo được thù; ngoài mặt vẫn chúc mừng Vương Lâm."},{"bridge":true,"khoang":"@c0468","text":"Trong khảo nghiệm áp lực phân loại đệ tử Tử hệ, Bạch Vi kiên trì thêm một lúc rồi than thầm, rơi xuống ngồi trên mặt đất."},{"bridge":true,"khoang":"@c0469","text":"Trong cuộc tranh phong hiệu, Bạch Vi cung kính tuyên bố bỏ cuộc."},{"chuong":"@c0470","importance":"minor","tieuDe":"Nhận ra Trần Đào","text":"Đệ tử Tử hệ Bạch Vi nhận ra Trần Đào khi hắn trở về, sắc mặt không tự nhiên và im lặng."}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Cùng phe Tử hệ; quan sát Vương Lâm trở lại với nụ cười kỳ dị","ghiChu":""},{"ten":"Đại sư huynh (Tử hệ)","tag":"doi-thu","quanHe":"Đối tượng báo thù","ghiChu":"Lo yêu linh thức tỉnh sẽ khôi phục bản lãnh đại sư huynh, hắn không báo được thù."},{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư tôn","ghiChu":"Trách sư tôn bất công đã cấy yêu linh vào thân đại sư huynh."},{"ten":"Trần Đào","tag":"su-mon","quanHe":"Đồng môn Tử hệ","ghiChu":"Nhận ra Trần Đào, sắc mặt không tự nhiên."}],"tuiDo":{},"tuViMoc":[]},"nguon":["@c0462","@c0464","@c0468","@c0469","@c0470"]},{"id":"xich-liet","name":"Xích Liệt","cn":"","aliases":["Xích Liệt sư thúc","Lão già mặt đỏ hồng bào"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ (cao thâm)","trangThai":"song","blurb":"Sư thúc trong Thiên Vận Tông, lão già hồng bào mặt đỏ đeo hồ lô rượu; chỉ một tiếng hét đã buộc cổ yêu rút lui.","vaiTro":"Sư thúc bậc trên trong Thiên Vận Tông","tinhCach":[{"text":"Phóng khoáng, ham rượu, tiếc chén rượu dở dang hơn cả việc đệ tử đánh nhau","chuong":"@c0463"},{"text":"Nể sợ tổ sư Thiên Vận Tử","chuong":"@c0463"}],"tabs":{"diem":[{"text":"Hóa từ một đám mây đỏ, sặc mùi rượu, mắng đệ tử đánh nhau làm dở chén rượu","chuong":"@c0463"},{"text":"Uy nghiêm trấn yêu: chỉ một tiếng hét “Nghiệt súc! Cút đi cho ta!” đã khiến cổ yêu run rẩy buông mồi","chuong":"@c0463"}],"kinhLich":[{"chuong":"@c0463","importance":"normal","tieuDe":"Xuất hiện chấm dứt trận đấu","text":"Khi cổ yêu định nuốt Hồn Thú của Vương Lâm, từ tổng tông Thiên Vận Tông vang tiếng hét của Xích Liệt buộc cổ yêu thu nhỏ rút về. Một đám mây đỏ hóa thành lão già hồng bào mặt đỏ đeo hồ lô, mắng các đệ tử đánh nhau và lo Thiên Vận Tử trách."},{"chuong":"@c0464","importance":"normal","tieuDe":"Bắt Triệu Sát Tinh trị tội","text":"Xích Liệt khẳng định yêu linh trong Triệu Sát Tinh vừa hình thành đã gượng dùng, túm hắn để sư phụ trừng phạt; tiết lộ sư phụ kỳ vọng cao ở Vương Lâm và đại sư huynh sẽ không xuất hiện tranh danh hiệu Thiên Vận Thất Tử, rồi hóa mây đỏ mang Triệu Sát Tinh bay đi."},{"chuong":"@c0464","importance":"minor","tieuDe":"Báo lịch giảng đạo","text":"Trước khi rời đi, Xích Liệt ôm quyền xin lỗi các tu sĩ tông phái và thông báo hôm sau là ngày sư huynh Thiên Vận Tử giảng đạo."}],"tuVi":"Cảnh giới chưa nêu rõ, song uy thế đủ trấn áp cổ yêu chỉ bằng một tiếng hét.","nhanMach":[{"ten":"Triệu Tinh Sát","tag":"su-mon","quanHe":"Đệ tử bậc dưới trong tông","ghiChu":"Triệu Tinh Sát tham kiến, từng gặp mấy ngàn năm trước."},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Đệ tử trong tông","ghiChu":"Tiếng hét của Xích Liệt vô tình cứu Hồn Thú của Vương Lâm."},{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Tổ sư mà Xích Liệt nể sợ","ghiChu":"Sợ bị Thiên Vận Tử trách phạt."},{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư huynh","ghiChu":"Báo lịch giảng đạo hôm sau của sư huynh."},{"ten":"Triệu Tinh Sát","tag":"khac","quanHe":"Đệ tử cháu (lão đại Tử hệ) bị áp giải","ghiChu":"Túm đi sau khi hắn gượng dùng yêu linh chưa luyện hóa."}],"tuiDo":{"phapBao":[{"ten":"Hồ lô lớn","loai":"vật đựng rượu","moTa":"Hồ lô lớn đeo sau lưng, đựng rượu; Xích Liệt sặc mùi rượu khi xuất hiện.","nguon":"@c0463"}]},"tuViMoc":[]},"nguon":["@c0463","@c0464"]},{"id":"khuong-thien-ton","name":"Khương Thiên Tôn","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thủy Vân Môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Vấn Đỉnh Hậu Kỳ","trangThai":"song","blurb":"Trưởng lão Vấn Đỉnh Hậu Kỳ của Thủy Vân Môn; người nhận ra hư ảnh là cổ yêu trong truyền thuyết thượng cổ và gọi tên Yêu lực.","vaiTro":"Trưởng lão Thủy Vân Môn, kiến thức uyên bác về thượng cổ","tinhCach":[{"text":"Trầm tĩnh, ngồi im suốt bảy ngày quan sát","chuong":"@c0463"}],"tabs":{"diem":[{"text":"Suốt bảy ngày ngồi im, chỉ nhẹ giọng khi nhận ra cổ yêu truyền thuyết","chuong":"@c0463"}],"kinhLich":[{"chuong":"@c0463","importance":"normal","tieuDe":"Nhận ra Cổ Yêu và Yêu lực","text":"Khi hư ảnh yêu vật xuất hiện, Khương Thiên Tôn nghi đó là cổ yêu trong truyền thuyết thượng cổ và xác nhận “Rất giống”. Lúc khí tức cổ yêu vượt xa linh lực, sánh ngang tiên lực và ma hỏa của Vương Lâm, ông gọi đó là “Yêu lực”."}],"tuViMoc":[{"chuong":"@c0463","canhGioi":"Vấn Đỉnh Hậu Kỳ","text":"Ra mặt với cảnh giới Vấn Đỉnh Hậu Kỳ, một trong các Vấn Đỉnh trưởng lão hiện diện.","importance":"major"}],"nhanMach":[],"tuiDo":{}},"nguon":["@c0463"]},{"id":"nam-tu-ho-vuong-thanh-tong","name":"Nam tử họ Vương (Thanh Tông)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thanh Tông","trangThai":"gan-bo"},{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Nửa bước Vấn Đỉnh","trangThai":"song","blurb":"Đệ tử Thanh Tông của Thiên Vận Tông, mặt lạnh như băng, đã bước nửa bước vào Vấn Đỉnh — vượt cả Tư Mã Như Phong.","vaiTro":"Đệ tử mạnh của Thanh Tông trong lễ giảng đạo Thiên Vận Tử","tinhCach":[{"text":"Mặt lạnh như băng, ít biểu lộ","chuong":"@c0464"}],"tabs":{"diem":[{"text":"Nửa bước Vấn Đỉnh, vượt Tư Mã Như Phong","chuong":"@c0464"}],"kinhLich":[{"chuong":"@c0464","importance":"normal","tieuDe":"Lộ diện trong lễ giảng đạo","text":"Theo đoàn Thanh Tông kính bái tổng tông trong lễ giảng đạo Thiên Vận Tử; Vương Lâm quét mắt nhận ra hắn đã bước nửa bước vào Vấn Đỉnh, vượt Tư Mã Như Phong."}],"tuViMoc":[{"chuong":"@c0464","canhGioi":"Nửa bước Vấn Đỉnh","text":"Tu vi đã bước nửa bước vào Vấn Đỉnh, vượt cả Tư Mã Như Phong Anh Biến đại viên mãn.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Cùng dự lễ giảng đạo Thiên Vận Tử","ghiChu":"Bị Vương Lâm nhận ra tu vi nửa bước Vấn Đỉnh."},{"ten":"Tư Mã Như Phong","tag":"doi-thu","quanHe":"Cùng sáu tông Thiên Vận Tông","ghiChu":"Tu vi vượt Tư Mã Như Phong."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0464"]},{"id":"nguoi-trung-nien-cam-tong","name":"Người trung niên Cam Tông","cn":"","aliases":["Người đàn ông trung niên (Cam Tông)"],"gioiTinh":"nam","theLuc":[{"ten":"Cam Tông","trangThai":"gan-bo"},{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến Hậu Kỳ","trangThai":"song","blurb":"Đệ tử vị trí thứ tư Cam Tông (Chanh Tông) của Thiên Vận Tông; năm xưa ở tiên giới từng dùng Sát Khí Huyết Tinh đánh nhau với Sất Hổ.","vaiTro":"Cao thủ Cam Tông Vương Lâm nhận ra trong lễ giảng đạo","tinhCach":[],"tabs":{"diem":[{"text":"Năm xưa đánh Sất Hổ ở tiên giới bằng Sát Khí Huyết Tinh","chuong":"@c0464"}],"kinhLich":[{"chuong":"@c0464","importance":"normal","tieuDe":"Tái xuất trong lễ giảng đạo","text":"Đứng vị trí thứ tư đoàn Cam Tông trong lễ giảng đạo Thiên Vận Tử; Vương Lâm nhận ra hắn chính là người năm xưa đánh nhau với Sất Hổ ở tiên giới, khi đó chưa tới Anh Biến nay đã đạt Anh Biến Hậu Kỳ."}],"tuViMoc":[{"chuong":"@c0464","canhGioi":"Anh Biến Hậu Kỳ","text":"Năm xưa ở tiên giới chưa tới Anh Biến, nay đã Anh Biến Hậu Kỳ.","importance":"major"}],"nhanMach":[{"ten":"Sất Hổ","tag":"doi-thu","quanHe":"Đối thủ trận đánh năm xưa ở tiên giới","ghiChu":"Từng dùng Sát Khí Huyết Tinh đánh nhau với Sất Hổ."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Cùng dự lễ giảng đạo, bị nhận ra","ghiChu":"Vương Lâm nhận ra qua ký ức tiên giới."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Sát Khí Huyết Tinh","trangThai":"dang-co","moTa":"Thần thông/pháp thuật từng dùng đánh Sất Hổ ở tiên giới năm xưa.","nguon":"@c0464"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0464"]},{"id":"ton-truong-lao","name":"Tôn trưởng lão","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Tu chân liên minh","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (cao thủ tột bậc tiên giới)","trangThai":"song","blurb":"Cao thủ uy áp tột bậc từ tu chân liên minh, được Thiên Vận Tử mời tới dự đại thọ vạn năm với danh nghĩa lão bằng hữu.","vaiTro":"Lão bằng hữu khách quý của Thiên Vận Tử, cao thủ tu chân liên minh","tinhCach":[{"text":"Hào sảng, thân thiết suồng sã với Thiên Vận Tử, gọi đối phương là Thiên Vận lão quái và đùa cợt thoải mái.","chuong":"@c0465"},{"text":"Uy áp khủng khiếp, chỉ một ánh mắt khiến các cao thủ phải cúi đầu.","chuong":"@c0465"}],"tabs":{"diem":[{"text":"Giáng lâm bằng đạo kim quang vạn trượng ngưng tụ thành trận pháp khổng lồ, khiến mặt trời mất màu, trời đất ảm đạm.","chuong":"@c0465"},{"text":"Dáng vẻ khoảng bốn mươi tuổi, thân hình cường tráng như pho tượng chiến tiên, mặt cương nghị, mắt như có tia chớp, mặc trường bào màu tím.","chuong":"@c0465"},{"text":"Nuôi một con tiểu điêu ba mắt đậu trên vai, tốc độ nhanh hơn tia chớp vô số lần.","chuong":"@c0465"}],"kinhLich":[{"chuong":"@c0465","importance":"normal","tieuDe":"Giáng lâm thọ yến Thiên Vận Tử","text":"Được Thiên Vận Tử mời từ hư không, Tôn trưởng lão hiện thân giữa đại thọ vạn năm, uy áp khiến cao thủ phải cúi đầu. Hắn tặng một thanh phi kiếm trung phẩm tiên khí ngưng luyện vạn năm làm hậu lễ, rồi ngồi một bên nghe Thiên Vận Tử giảng đạo."},{"bridge":true,"khoang":"@c0466–@c0466","text":"Trưởng lão đến từ liên minh tu chân dự buổi giảng đạo; tử điêu đậu lên vai lão nhai nuốt tiên ngọc, lão mỉm cười gật đầu với Vương Lâm. Khi Thiên Vận Tử nhắc tới ‘hắn’, sắc mặt lão lập tức khó coi, hồi tưởng mang theo nhiều vẻ sợ hãi vì rõ ràng biết đó là ai."},{"bridge":true,"khoang":"@c0467","text":"Dự lễ đại thọ vạn năm, Tôn trưởng lão sắc mặt khó coi và muốn ngăn Thiên Vận Tử nhắc về “hắn” nhưng đành để lão nói; vốn quen biết Lăng Thiên Hầu nên có lời chào hỏi khi vị Kiếm Tôn xuất hiện."},{"chuong":"@c0470","importance":"minor","tieuDe":"Thẩm định kỳ bảo","text":"Tôn trưởng lão xác nhận đoá hoa Trần Đào dâng là Thất thải lưu ly quang, nhận xét hoả hậu còn kém cánh thứ bảy."}],"tuViMoc":[],"tuVi":"Cao thủ tột bậc của tu chân liên minh; thực lực không rõ cảnh giới nhưng uy áp khiến các cao thủ Thiên Vận Tông phải cúi đầu.","nhanMach":[{"ten":"Thiên Vận Tử","tag":"ban-be","quanHe":"Lão bằng hữu, được mời dự đại thọ vạn năm","ghiChu":"Xưng hô thân mật, gọi nhau là lão quái / Thiên Vận lão quái."},{"ten":"Côn Bằng Tử","tag":"khac","quanHe":"Người được Thiên Vận Tử chuyển tặng phi kiếm của ông","ghiChu":""},{"ten":"Vương Lâm","tag":"khac","quanHe":"Đệ tử Tử Hệ bị tiểu điêu ba mắt của ông dò xét riêng","ghiChu":""},{"ten":"Lăng Thiên Hầu","tag":"dong-minh","quanHe":"quen biết","ghiChu":"Lăng Thiên Hầu chào hỏi Tôn trưởng lão như người quen khi tới dự đại thọ."}],"tuiDo":{"phapBao":[{"ten":"Phi kiếm màu vàng (trung phẩm tiên khí)","loai":"phi-kiem","trangThai":"da-dung","moTa":"Trung phẩm tiên khí do Tôn trưởng lão tự ngưng luyện vạn năm, đem tặng Thiên Vận Tử làm hậu lễ thọ yến (sau đó được tặng lại Côn Bằng Tử).","nguon":"@c0465"}],"linhThu":[{"ten":"Tiểu điêu ba mắt","moTa":"Con chim toàn thân màu tím, ba mắt phát tia sáng âm u, đậu trên vai Tôn trưởng lão; tốc độ nhanh hơn tia chớp vô số lần. Trong thọ yến nó bay tới đậu vai Vương Lâm dò xét.","nguon":"@c0465"}]}},"nguon":["@c0465","@c0466","@c0467","@c0470"]},{"id":"con-bang-tu","name":"Côn Bằng Tử","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Hoàng Hệ (Thiên Vận Tông)","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Người đứng đầu Hoàng Hệ của Thiên Vận Tông, được Thiên Vận Tử tặng lại phi kiếm trung phẩm tiên khí trong thọ yến.","vaiTro":"Đầu lĩnh Hoàng Hệ Thiên Vận Tông","tinhCach":[{"text":"Trung thành, dễ xúc động trước ân điển của sư tôn; run rẩy tạ ơn khi nhận bảo vật.","chuong":"@c0465"}],"tabs":{"diem":[{"text":"Đứng đầu Hoàng Hệ, được Thiên Vận Tử ban tặng phi kiếm trung phẩm tiên khí ngay tại thọ yến.","chuong":"@c0465"}],"kinhLich":[{"chuong":"@c0465","importance":"normal","tieuDe":"Nhận phi kiếm trung phẩm tiên khí","text":"Tại đại thọ vạn năm, Thiên Vận Tử nhận thanh phi kiếm trung phẩm tiên khí của Tôn trưởng lão rồi ném tặng lại cho Côn Bằng Tử; hắn run lên xúc động, cung kính tạ ơn sư tôn."},{"chuong":"@c0469","importance":"normal","tieuDe":"Nhận phong hiệu Thiên Vận Thất tử Hoàng hệ","text":"Sau khi Vận Đường nhường ngôi và đề cử, Côn Bằng Tử (Nhị sư đệ Hoàng hệ) được Thiên Vận Tử trao tinh thể vàng — dấu hiệu phong hiệu Thiên Vận Thất tử của Hoàng hệ, hứa truyền một bản Hạ phẩm Tiên thuật đầy đủ nếu giữ phong hiệu ngàn năm và một bảo mệnh pháp bảo khi xuất quan. Hắn kích động quỳ bái nhận lời rồi vào bế quan cảm thụ tinh thể vàng."}],"tuViMoc":[],"tuVi":"Không rõ cảnh giới; là đầu lĩnh Hoàng Hệ Thiên Vận Tông.","nhanMach":[{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư tôn / thủy tổ Thiên Vận Tông, ban tặng phi kiếm tiên khí","ghiChu":""},{"ten":"Tôn trưởng lão","tag":"an-nhan","quanHe":"Người ngưng luyện thanh phi kiếm mà hắn được nhận","ghiChu":""},{"ten":"Vận Đường","tag":"su-mon","quanHe":"Đại sư huynh Hoàng hệ","ghiChu":"Vận Đường chủ động bỏ cuộc, đề cử Côn Bằng Tử là người thích hợp nhất với phong hiệu."}],"tuiDo":{"phapBao":[{"ten":"Phi kiếm màu vàng (trung phẩm tiên khí)","loai":"phi-kiem","trangThai":"dang-co","moTa":"Trung phẩm tiên khí do Tôn trưởng lão ngưng luyện vạn năm, được Thiên Vận Tử chuyển tặng tại thọ yến.","nguon":"@c0465"}]}},"nguon":["@c0465","@c0469"]},{"id":"hac-y-nhan-mat-seo","name":"Hắc y nhân (mặt sẹo)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"","trangThai":"khong-ro","blurb":"Tu sĩ mặc hắc y tỏa hung khí, mặt có vết sẹo hung ác chạy từ mặt xuống cổ, hỏi Thiên Vận Tử về bước thứ ba của tu đạo.","vaiTro":"Tu sĩ bí ẩn dự buổi giảng đạo của Thiên Vận Tử.","tinhCach":[{"text":"Trầm tĩnh nhưng ẩn chứa hung khí dày đặc, khiến trong vòng mười trượng quanh thân không tu sĩ nào dám lại gần.","chuong":"@c0466"}],"tabs":{"diem":[{"text":"Quanh thân mười trượng không ai dám lại gần, hung khí cuộn trào, mặt có vết sẹo hung ác từ mặt xuống cổ.","chuong":"@c0466"}],"kinhLich":[{"chuong":"@c0466","importance":"normal","tieuDe":"Hỏi về bước thứ ba","text":"Giữa buổi giảng đạo trên tường vân, hắc y nhân trầm giọng hỏi Thiên Vận Tử về bước thứ ba của tu đạo, dẫn tới phần giải thích chữ ‘đạo’ và thiên vận."}],"tuViMoc":[],"nhanMach":[{"ten":"Thiên Vận Tử","tag":"khac","quanHe":"Hỏi Thiên Vận Tử về bước thứ ba của tu đạo trong buổi giảng.","ghiChu":""}],"tuiDo":{}},"nguon":["@c0466"]},{"id":"han-bi-an","name":"Hắn (nhân vật bí ẩn)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"","trangThai":"khong-ro","blurb":"Nhân vật bí ẩn Thiên Vận Tử gặp ba ngàn năm trước, khiến hắn tin có bước thứ ba của tu đạo; Tôn trưởng lão biết và lộ vẻ sợ hãi khi nhớ lại.","vaiTro":"Nhân vật cực mạnh được nhắc tới, chưa lộ diện.","tinhCach":[],"tabs":{"diem":[{"text":"Sự tồn tại đủ khiến cả Thiên Vận Tử thay đổi nhận thức về bước thứ ba và khiến Tôn trưởng lão sợ hãi.","chuong":"@c0466"}],"kinhLich":[{"chuong":"@c0466","importance":"normal","tieuDe":"Được nhắc tới","text":"Thiên Vận Tử kể rằng ba ngàn năm trước nhờ gặp ‘hắn’ mới tin có bước thứ ba của tu đạo; Tôn trưởng lão hiển nhiên biết ‘hắn’ là ai và lộ vẻ sợ hãi."},{"bridge":true,"khoang":"@c0467","text":"Được Thiên Vận Tử tiết lộ là kẻ duy nhất lão từng biết đã đạt tới bước thứ ba, từng khiến Tu Chân Liên Minh nếm đau khổ một lần duy nhất; như đoá phù dung sớm nở tối tàn, nay đã biệt tích không tung tích, danh tính bỏ ngỏ."}],"tuViMoc":[],"nhanMach":[{"ten":"Thiên Vận Tử","tag":"khac","quanHe":"Người Thiên Vận Tử gặp ba ngàn năm trước, làm hắn tin có bước thứ ba.","ghiChu":""}],"tuiDo":{}},"nguon":["@c0466","@c0467"]},{"id":"lang-thien-hau","name":"Lăng Thiên Hầu","aliases":["Kiếm Tôn Lăng Thiên Hầu","Lăng Thiên Hậu"],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c0467","importance":"normal","tieuDe":"Kiếm Tôn cưỡi biển phi kiếm dự đại thọ","text":"Kiếm Tôn Lăng Thiên Hầu, Tông chủ Đại La Kiếm Tông trên Thiên Vận Tinh, xuất hiện cùng sấm sét và vô số kiếm quang: một lão già áo xanh râu trắng gầy gò mang khí tức thiên uy, sau lưng có bốn bóng kiếm hư ảo, dưới chân là xà hình bảo kiếm đầy máu tanh. Hắn dẫn hơn vạn đệ tử áo đen đeo kiếm cổ tới chúc thọ, chào hỏi Tôn trưởng lão và lạnh lùng đồng ý làm đối tượng cho Thiên Vận Tử thi triển Tiên thuật."},{"chuong":"@c0468","importance":"normal","tieuDe":"Đối đầu Thiên Vận Tử tại đại thọ","text":"Kiếm Tôn Lăng Thiên Hầu dẫn hơn vạn đệ tử Đại La Kiếm Tông tới chúc thọ; khi Thiên Vận Tử thi triển Dẫn Tiên thuật cuốn đệ tử đi, lão thúc xà hình phi kiếm lao lên rồi triệu Kỳ Lân thú từ mi tâm phản kích, nhưng cuối cùng nhẫn nhịn gọi kiếm tiên về, chờ ba ngày đệ tử trở về."},{"bridge":true,"khoang":"@c0469","text":"Khi Thiên Vận Tử trao phong hiệu Thiên Vận Thất tử cho Côn Bằng Tử, Kiếm Tôn Lăng Thiên Hầu lộ một tia khinh thường."},{"chuong":"@c0470","importance":"minor","tieuDe":"Kinh ngạc trước Hồn thú","text":"Là quan khách mừng thọ, Kiếm Tôn Lăng Thiên Hầu lộ vẻ kinh ngạc khi thấy Hồn thú khổng lồ Vương Lâm triệu ra từ Xạ Thần xa."},{"chuong":"@c0472","importance":"normal","tieuDe":"Nhắc ước hẹn Đông Hải Yêu Linh chi môn","text":"Rời đại thọ sớm bằng kiếm quang; trước khi đi nhắc lại ước hẹn với Thiên Vận Tử rằng ba tháng sau lão phải tuyển người tiến vào Đông Hải Yêu Linh chi môn."}],"nhanMach":[{"ten":"Thiên Vận Tử","tag":"doi-thu","quanHe":"đồng cấp/đối thủ thực lực","ghiChu":"Tu vi và thực lực môn phái của hai bên gần tương đương; Lăng Thiên Hầu đồng ý làm đối tượng cho Thiên Vận Tử thi triển Dẫn Tiên thuật."},{"ten":"Tôn trưởng lão","tag":"dong-minh","quanHe":"quen biết","ghiChu":"Chào hỏi Tôn trưởng lão khi tới dự đại thọ."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"ân oán tiềm ẩn","ghiChu":"Vương Lâm nhận ra thanh xà hình bảo kiếm của Lăng Thiên Hầu là Vũ chi đệ nhị kiếm bị cướp ở Tiên giới năm xưa."},{"ten":"Thiên Vận Tử","tag":"doi-thu","quanHe":"Chủ nhân đại thọ làm nhục mình","ghiChu":"Thiên Vận Tử cuốn đi đệ tử Đại La Kiếm Tông của lão; Lăng Thiên Hầu trách móc nhưng biết thân phận đối phương nên đành chờ ba ngày."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Đệ tử Tử hệ trong đám đông","ghiChu":"Kỳ Lân thú của Lăng Thiên Hầu cộng hưởng tiếng gầm với Tôn Hồn Phiên trong người Vương Lâm."},{"ten":"Thiên Vận Tử","tag":"khac","quanHe":"Đại lão có ước hẹn","ghiChu":"Ước hẹn Đông Hải Yêu Linh chi môn."}],"tuiDo":{"phapBao":[{"ten":"Vũ chi đệ nhị kiếm","tenCu":"Xà hình bảo kiếm","trangThai":"dang-co","moTa":"Bảo kiếm hình con rắn đầy máu tanh dưới chân Lăng Thiên Hầu, tế luyện bằng phương pháp khiến người nhìn tâm thần đại chấn; chính là Vũ chi đệ nhị kiếm hắn cướp ở Tiên giới năm đó.","nguon":"@c0467"}]},"tuViMoc":[]},"nguon":["@c0467","@c0468","@c0469","@c0470","@c0472"]},{"id":"lao-tam-hoang-he-thien-van","name":"Lão Tam (Hoàng hệ)","gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"trangThai":"mat-tich","blurb":"Đệ tử Hoàng hệ của Thiên Vận Tử, ba mươi năm trước từng đạt phong hiệu Thiên Vận Thất tử rồi mất tích thần bí khi ra tinh không.","vaiTro":"Nhân vật được nhắc tên","tabs":{"diem":[{"text":"Từng mang phong hiệu Thiên Vận Thất tử nhưng một lần ra tinh không thì bặt vô âm tín cho tới nay","chuong":"@c0468"}],"kinhLich":[{"chuong":"@c0468","importance":"minor","tieuDe":"Mất tích ở tinh không","text":"Ba mươi năm trước, lão Tam Hoàng hệ đạt phong hiệu Thiên Vận Thất tử, nhưng trong một lần ra tinh không thì mất tích thần bí, đến nay vẫn bặt tin."}],"tuViMoc":[],"nhanMach":[{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư phụ","ghiChu":"Thiên Vận Tử nhắc tới lão Tam khi tuyên bố tranh đoạt phong hiệu Thiên Vận Thất tử cho Hoàng hệ và Tử hệ."}],"tuiDo":{}},"nguon":["@c0468"]},{"id":"van-duong","name":"Vận Đường","aliases":["Đại sư huynh Hoàng hệ","Lão đại Hoàng hệ"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"},{"ten":"Hoàng hệ","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Lão đại Hoàng hệ, dung mạo xấu xí nhiều nếp nhăn; từng làm Thiên Vận Thất tử hơn 800 năm rồi bị lão Tam đoạt, tính nhàn nhã không tranh đoạt nhưng ẩn giấu điều quỷ dị.","vaiTro":"Đại sư huynh Hoàng hệ, người chủ động nhường phong hiệu nhưng để lộ biểu hiện bí ẩn khiến Vương Lâm và Thiên Vận Tử để ý.","tinhCach":[{"text":"Nhàn nhã, không có tâm tranh đoạt, chỉ thích tu luyện thong dong","chuong":"@c0469"},{"text":"Ẩn giấu điều quỷ dị — mắt co rút và lộ vẻ sợ hãi khi tinh thể vàng xuất hiện","chuong":"@c0469"}],"tabs":{"diem":[{"text":"Từng làm Thiên Vận Thất tử hơn 800 năm rồi bị lão Tam đoạt mất","chuong":"@c0469"},{"text":"Theo Thiên Vận Tử trước cả Côn Bằng Tử (hơn 2000 năm), tính tình quái gỡ không tiếp xúc người khác","chuong":"@c0469"}],"kinhLich":[{"chuong":"@c0469","importance":"normal","tieuDe":"Nhường phong hiệu, đề cử Côn Bằng Tử","text":"Trong cuộc tranh phong hiệu Hoàng hệ, Vận Đường — chỉ còn lại cùng Côn Bằng Tử — cung kính xin bỏ cuộc, tự nhận không có tâm tranh đoạt và đề cử Nhị sư đệ Côn Bằng Tử là người thích hợp nhất với phong hiệu. Khi tinh thể vàng từ mi tâm Thiên Vận Tử bay ra, hai mắt lão co rút rồi lập tức bình tĩnh; bị Vương Lâm nhìn lâu, lão ngẩng đầu quét mắt rồi khoé miệng mỉm cười, sau lại run sợ trước ánh mắt âm trầm của Thiên Vận Tử."}],"tuViMoc":[],"tuVi":"Tu vi chưa rõ; che giấu rất giỏi, từng đủ sức làm Thiên Vận Thất tử Hoàng hệ hơn 800 năm.","nhanMach":[{"ten":"Côn Bằng Tử","tag":"su-mon","quanHe":"Nhị sư đệ Hoàng hệ","ghiChu":"Vận Đường nhường phong hiệu, đề cử Côn Bằng Tử."},{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư phụ","ghiChu":"Bị Thiên Vận Tử nhìn bằng ánh mắt âm trầm khiến run lòng cúi đầu."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Sư đệ đồng môn (Lão Thất)","ghiChu":"Vương Lâm phát hiện biểu hiện quỷ dị của lão; ánh mắt sợ hãi của lão khiến Vương Lâm do dự bỏ cuộc."}],"tuiDo":{}},"nguon":["@c0469"]},{"id":"tran-dao","name":"Trần Đào","aliases":["Tử hệ Lão Lục","Lão Lục"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"},{"ten":"Tử hệ","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Vấn Đỉnh kỳ","trangThai":"song","blurb":"Tử hệ Lão Lục, đệ tử lâu năm của Thiên Vận Tử, từng đạt phong hiệu Thiên Vận Thất tử trước thời Tôn Vân; trở về đòi tranh lại phong hiệu.","vaiTro":"Đệ tử kỳ cựu Tử hệ trở về tranh phong hiệu, đối thủ mới của Vương Lâm trong tiệc đại thọ.","tinhCach":[{"text":"Kiêu ngạo, khinh thường Vương Lâm, chỉ thừa nhận Tôn Vân mới là Thất sư đệ thật.","chuong":"@c0470"},{"text":"Hiếu chiến, hứng thú trước cường địch — xé áo lộ nửa thân, rút trường thằng nghênh chiến.","chuong":"@c0470"}],"tabs":{"diem":[{"text":"Từng đạt phong hiệu Thiên Vận Thất tử trước Tôn Vân, năm xưa thua Tôn Vân rồi rời tông ra tinh ngoại rèn luyện.","chuong":"@c0470"}],"kinhLich":[{"chuong":"@c0470","importance":"normal","tieuDe":"Trở về dâng kỳ bảo đòi phong hiệu","text":"Một đạo tử khí xông tới hiện ra Trần Đào, dâng cho Thiên Vận Tử đoá Thất thải lưu ly quang cướp được ở Hắc Mặc Tinh — thiên địa kỳ bảo xếp thứ 93 Tu Chân Liên Minh. Hắn đòi lại phong hiệu Thiên Vận Thất tử; khi Triệu Hân Mộng truyền âm về Tôn Vân, hắn biến sắc."},{"chuong":"@c0470","importance":"normal","tieuDe":"Giao chiến Vương Lâm","text":"Trần Đào (Vấn Đỉnh) đánh ấn quyết chấn nhiếp nhưng chỉ đẩy lùi Vương Lâm mười trượng nên kinh ngạc; hắn đẩy ngũ chuyển kim tiên lực của Vương Lâm lên cửu chuyển phản công, rồi nổ tan đòn nuốt của Hồn thú khiến quần áo rách bươm. Hứng thú trước cường địch, hắn xé áo lộ nửa thân, rút ra trường thằng đen như sợi gân sinh vật toả khí tức hoang dã (trận chưa dứt)."},{"chuong":"@c0471","importance":"normal","tieuDe":"Khốn Hồn thú bằng Long cân","text":"Trần Đào khoe Long cân rút từ xác một con yêu long ở Yêu Tinh, vung từ góc độ khó tin buộc lấy cổ Hồn thú của Vương Lâm rồi đứng trên đầu nó siết chặt khống chế."},{"chuong":"@c0471","importance":"normal","tieuDe":"Khẩu chiến và tấn công Vương Lâm","text":"Sau khi Vương Lâm mở phong ấn Xạ Thần xa khiến Hồn thú phản công, Trần Đào dựng tử sắc quang cầu phòng ngự nhưng vẫn bị tổn thương; hắn mỉa mai Vương Lâm “có tư cách làm sư đệ”, bị phản bác, rồi hóa tàn ảnh lao tới tấn công."},{"chuong":"@c0472","importance":"normal","tieuDe":"Thắng Vương Lâm đoạt phong hiệu","text":"Đỡ được hai đạo Hoàng tuyền chỉ của Vương Lâm nhờ trước khi trở về có kỳ ngộ đạt Vấn Đỉnh trung kỳ, thừa nhận một chỉ này vượt ngoài dự liệu. Thắng trận nên được Thiên Vận Tử trao phong hiệu Thiên Vận Thất tử của Tử hệ; lão điểm mi tâm đưa cảm ngộ phong hiệu vào người hắn."}],"tuViMoc":[{"chuong":"@c0470","canhGioi":"Vấn Đỉnh kỳ","text":"Trần Đào tu vi Vấn Đỉnh, đủ sức đẩy kim tiên lực lên cửu chuyển.","importance":"minor"},{"chuong":"@c0472","canhGioi":"Vấn Đỉnh trung kỳ","text":"Trước khi trở về tham dự đại thọ, nhờ một kỳ ngộ mà đạt tới Vấn Đỉnh trung kỳ, đủ sức đỡ Hoàng tuyền chỉ của Vương Lâm.","importance":"major"}],"nhanMach":[{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư phụ","ghiChu":"Đệ tử lâu năm, dâng kỳ bảo mừng đại thọ vạn năm của sư phụ."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Tranh phong hiệu Thiên Vận Thất tử","ghiChu":"Khinh thường rồi giao chiến với Vương Lâm."},{"ten":"Tôn Vân","tag":"doi-thu","quanHe":"Người từng đoạt phong hiệu của hắn","ghiChu":"Năm xưa thua Tôn Vân; thừa nhận Tôn Vân mới là Thất sư đệ thật."},{"ten":"Triệu Hân Mộng","tag":"su-mon","quanHe":"Đồng môn Tử hệ","ghiChu":"Triệu Hân Mộng truyền âm về Tôn Vân khiến hắn biến sắc."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ tại lễ chúc thọ","ghiChu":"Trần Đào (Vấn Đỉnh kỳ) tự xưng sư huynh, giao chiến với Vương Lâm."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Sư huynh đệ Tử hệ kiêm đối thủ","ghiChu":"Hẹn tái chiến với Vương Lâm sau khi đối phương đạt Vấn Đỉnh."},{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Trưởng bối Thiên Vận Tông","ghiChu":"Trao phong hiệu Thiên Vận Thất tử."}],"tuiDo":{"phapBao":[{"ten":"Trường thằng đen","trangThai":"dang-co","moTa":"Sợi dây như gân sinh vật rút ra từ thân, toả khí tức hoang dã, dùng đối phó Hồn thú.","nguon":"@c0470"}],"khac":[{"ten":"Thất thải lưu ly quang","moTa":"Đoá hoa kỳ bảo cướp ở Hắc Mặc Tinh, dâng cho Thiên Vận Tử.","trangThai":"da-dung","nguon":"@c0470"}]}},"nguon":["@c0470","@c0471","@c0472"]},{"id":"lao-gia-mat-do-ho-lo-do","name":"Lão già mặt đỏ (mang hồ lô đỏ)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Vị khách lạ mặt đỏ mang hồ lô đỏ lớn đến lễ chúc thọ, vừa uống rượu vừa nhận ra Hoàng tuyền chỉ của Vương Lâm giống hệt sát chiêu của một “người điên” lão từng gặp.","vaiTro":"Nhân vật bí ẩn quan khán tại lễ chúc thọ","tinhCach":[{"text":"Phóng khoáng, mê rượu","chuong":"@c0471"}],"tabs":{"diem":[{"text":"Nhận ra mối liên hệ giữa sát chiêu Hoàng tuyền chỉ và một “lão quái / người điên” lão từng gặp thuở mới đến nơi này","chuong":"@c0471"}],"kinhLich":[{"chuong":"@c0471","importance":"normal","tieuDe":"Khách chúc thọ nhận ra sát chiêu","text":"Lão già mặt đỏ mang hồ lô đỏ đến chúc thọ, vừa uống rượu vừa ngạc nhiên khi thấy Hoàng tuyền chỉ của Vương Lâm giống hệt sát chiêu của “người điên kia” mà lão từng gặp khi mới tới nơi này; danh tính lão chưa lộ."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Quan khán nhận ra sát chiêu","ghiChu":"Thấy Hoàng tuyền chỉ của Vương Lâm giống sát chiêu một nhân vật bí ẩn lão từng gặp."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0471"]},{"id":"thien-van-tu-ao-xam","name":"Thiên Vận Tử áo xám","aliases":["Người áo xám","Hơn một người"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ (siêu việt Vấn Đỉnh)","trangThai":"khong-ro","blurb":"Một Thiên Vận Tử mặc áo bào màu tro, mắt xám, trẻ tuổi hơn các Thiên Vận Tử khác — là người ‘hơn một người’ (thứ 3601) trong thế giới bảy màu, nắm giữ Sát Lục Tiên quyết.","vaiTro":"Nhân vật bí ẩn xuất hiện trong tâm thần Thiên Vận Tử, mời truyền Sát Lục Tiên quyết cho Vương Lâm.","tinhCach":[{"text":"Lạnh lùng, sát khí cực mạnh — chỉ một chữ làm sụp phong ấn của 3600 Thiên Vận Tử","chuong":"@c0474"},{"text":"Kỳ dị, kiêng kỵ con số bảy","chuong":"@c0474"}],"tabs":{"diem":[{"text":"Là ‘hơn một người’ — thực thể thứ 3601 trong thế giới bảy màu, không có tiên lực dao động, mọi công kích xuyên qua như ảo ảnh","chuong":"@c0474"},{"text":"Sát khí mạnh nhất Vương Lâm từng gặp; một chữ ‘Cút!’ đẩy lui 3600 Thiên Vận Tử mấy vạn dặm","chuong":"@c0474"},{"text":"Nắm giữ Sát Lục Tiên quyết, thân được hàng tỷ Sinh chi lạc ấn thủ hộ","chuong":"@c0474"}],"kinhLich":[{"chuong":"@c0474","importance":"normal","tieuDe":"Lộ diện ‘hơn một người’ trong thế giới bảy màu","text":"Khi Vương Lâm vào thế giới bảy màu chọn thần thông, người áo xám ngồi thổ nạp bất động giữa 3600 Thiên Vận Tử. Sát khí của lão khiến cả 3600 Thiên Vận Tử hô ‘Phong!’ phong ấn, nhưng một chữ ‘Cút!’ làm phong ấn sụp đổ, để lộ tổng số 3601 — hơn một người."},{"chuong":"@c0474","importance":"normal","tieuDe":"Mời truyền Sát Lục Tiên quyết","text":"Sau sáu lần chạm mặt, người áo xám hỏi Vương Lâm có phải đệ tử Thiên Vận Tử, tiết lộ lão được đưa tới vì Sát Lục Tiên quyết, ra điều kiện ‘không lưu người sống’. Khi Vương Lâm từ chối, lão không đáp câu hỏi về quan hệ với sư phụ, hoá một ngọc giản từ bụi khí để lại rồi biến mất."}],"tuVi":"Cảnh giới chưa nói rõ nhưng siêu việt Vấn Đỉnh; thân được hàng tỷ Sinh chi lạc ấn thủ hộ, dù Thiên Vận Tinh sụp đổ cũng bình yên vô sự.","nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người thứ sáu được đưa tới; được mời truyền Sát Lục Tiên quyết nhưng từ chối, vẫn được để lại ngọc giản","ghiChu":"@c0474"},{"ten":"Thiên Vận Tử","tag":"khac","quanHe":"Có hứa hẹn từ trước nên mới chịu truyền cho đệ tử của Thiên Vận Tử; quan hệ cụ thể chưa tiết lộ","ghiChu":"@c0474"}],"tuiDo":{"congPhap":[{"ten":"Sát Lục Tiên quyết","trangThai":"dang-co","moTa":"Tiên quyết bắt chước từ một loại Tiên thuật vô danh, dựa vào giết chóc đoạt sinh lực ngưng kết Sinh chi lạc ấn phòng thủ.","nguon":"@c0474"}]}},"nguon":["@c0474"]},{"id":"hua-van-son","name":"Hứa Vân Sơn","cn":"","aliases":["Thiếu Tông Huyền Uyên Phái"],"gioiTinh":"nam","theLuc":[{"ten":"Huyền Uyên Phái","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến Trung kỳ","trangThai":"song","blurb":"Thiếu Tông của Huyền Uyên Phái trên Địa Tinh, chủ động ra đón và kết giao với Vương Lâm.","vaiTro":"Thiếu Tông Huyền Uyên Phái, người dẫn dắt Vương Lâm khi tới Địa Tinh và đưa hắn nhậm chức sứ giả Linh Nhạc quốc.","tinhCach":[{"text":"Tinh ý, biết nhìn xa, chủ động kết giao với người có tiềm lực lớn","chuong":"@c0476"}],"tabs":{"diem":[{"text":"Cầm bảo phiến ngọc bích, phong thái ung dung của một Thiếu Tông","chuong":"@c0476"},{"text":"Khi biết sứ giả mới là Tử hệ Lão Thất Vương Lâm thì rung động muốn kết giao sớm","chuong":"@c0476"}],"kinhLich":[{"chuong":"@c0476","importance":"normal","tieuDe":"Nghênh đón sứ giả Tử hệ","text":"Ba ngày trước biết tin từ một bằng hữu Thiên Vận Tông rằng có người Tử hệ sẽ tới Địa Tinh làm sứ giả Linh Nhạc quốc; khi biết đó là Vương Lâm — đệ tử mới của Thiên Vận Tử — hắn cầm bảo phiến ngọc bích cùng mấy Trưởng lão tóc bạc ra Truyền tống trận chờ đón, ôm quyền xưng Thiếu tông và mời với tư cách chủ nhà."},{"bridge":true,"khoang":"@c0476–@c0476","text":"Sau hai ngày quan hệ đã hoà hợp, Hứa Vân Sơn đưa Vương Lâm tới Linh Nhạc quốc nhận chức sứ giả."},{"bridge":true,"khoang":"@c0477","text":"Cùng Vương Lâm bay tới Linh Nhạc quốc đưa hắn nhậm chức Sứ giả, cười cáo từ gọi Vương Lâm là Vương huynh, hẹn ngày sau uống rượu rồi hóa sét bay đi."}],"tuViMoc":[{"chuong":"@c0476","canhGioi":"Anh Biến Trung kỳ","text":"Tu vi ngang hàng Vương Lâm khi gặp mặt.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Chủ động ra đón và kết giao, làm chủ nhà dẫn Vương Lâm tới Linh Nhạc quốc"},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Đưa Vương Lâm đến nhậm chức Sứ giả Huyền Uyên Phái, xưng hô thân thiết","ghiChu":"@c0477"}],"tuiDo":{"phapBao":[{"ten":"Bảo phiến ngọc bích","moTa":"Cây quạt gấp màu ngọc bích Hứa Vân Sơn cầm khi ra đón Vương Lâm.","nguon":"@c0476"}]}},"nguon":["@c0476","@c0477"]},{"id":"trieu-tu","name":"Triệu Tứ","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Huyền Uyên Phái","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Hoá Thần (hướng tới hậu kỳ)","trangThai":"song","blurb":"Tu sĩ Huyền Uyên Phái vận hành Truyền tống trận, người tiễn Vương Lâm tới Địa Tinh.","vaiTro":"Tu sĩ trông coi và kích hoạt Truyền tống trận của Huyền Uyên Phái.","tinhCach":[{"text":"Hâm mộ kẻ mạnh, chuyên tâm tu luyện","chuong":"@c0476"}],"tabs":{"diem":[{"text":"Kính gọi Vương Lâm là “Tử hệ Thất sư tổ”, hâm mộ nhìn theo sau khi tiễn","chuong":"@c0476"}],"kinhLich":[{"chuong":"@c0476","importance":"normal","tieuDe":"Kích hoạt Truyền tống trận tiễn Vương Lâm","text":"Triệu Tứ kết quyết đánh một đạo thanh quang vào Truyền tống trận mười dặm, khiến toàn trận chấn động và truyền Vương Lâm rời đi; sau đó hắn lẩm bẩm không biết Thất sư tổ tới Địa Tinh làm gì rồi khoanh chân thổ nạp, quyết sớm đạt Hoá Thần hậu kỳ."}],"tuViMoc":[{"chuong":"@c0476","canhGioi":"Hoá Thần","text":"Đang tu luyện hướng tới Hoá Thần hậu kỳ.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Vận hành Truyền tống trận tiễn Vương Lâm tới Địa Tinh, kính gọi là Thất sư tổ"}]},"nguon":["@c0476"]},{"id":"lao-to-huyen-minh","name":"Lão Tổ Huyền Minh","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Huyền Uyên Phái","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Vượt Vấn Đỉnh","trangThai":"song","blurb":"Lão Tổ đứng đầu Huyền Uyên Phái trên Địa Tinh, tu vi vượt quá Vấn Đỉnh.","vaiTro":"Người đứng đầu Huyền Uyên Phái, thế lực tu chân mạnh nhất Địa Tinh.","tinhCach":[],"tabs":{"diem":[{"text":"Tu vi vượt quá Vấn Đỉnh, là chỗ dựa của Huyền Uyên Phái","chuong":"@c0476"}],"kinhLich":[{"bridge":true,"khoang":"@c0476–@c0476","text":"Được nhắc tới là Lão Tổ đứng đầu Huyền Uyên Phái — Lục cấp tu chân quốc duy nhất trên Địa Tinh, tu vi vượt quá Vấn Đỉnh."}],"nhanMach":[]},"nguon":["@c0476"]},{"id":"thien-thai-lao-nhan","name":"Thiên Thai lão nhân","cn":"","aliases":["Lão nhân tóc bạc trắng","Cao thủ đệ nhất Linh Nhạc quốc"],"gioiTinh":"nam","theLuc":[{"ten":"Linh Nhạc quốc","trangThai":"gan-bo"},{"ten":"Ngũ Linh Sơn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến hậu kỳ đại viên mãn (một chân vào Vấn Đỉnh)","trangThai":"song","blurb":"Cao thủ đệ nhất Linh Nhạc quốc, lão nhân tóc bạc ở Ngũ Linh Sơn, tu vi gần chạm cảnh giới Vấn Đỉnh.","vaiTro":"Tu sĩ mạnh nhất Linh Nhạc quốc; sau khi thăm dò Vương Lâm và thấy Khuất thú thì khiếp sợ, hạ lệnh lập cấm địa quanh Thông Thiên tháp.","tinhCach":[{"text":"Điềm tĩnh, thận trọng, biết tiến thoái","chuong":"@c0477"}],"tabs":{"diem":[{"text":"Tu vi cao nhất Linh Nhạc quốc, đã đặt một chân vào cảnh giới Vấn Đỉnh","chuong":"@c0477"},{"text":"Hấp thu thái âm lực thổ nạp trên đỉnh Ngũ Linh Sơn","chuong":"@c0477"}],"kinhLich":[{"chuong":"@c0477","importance":"normal","tieuDe":"Thăm dò Vương Lâm, lập cấm địa","text":"Là cao thủ đệ nhất Linh Nhạc quốc, lão nhân đến Thông Thiên tháp thăm dò vị tân Sứ giả. Ba ngày sau trở về với sắc mặt cực kỳ khó coi, mắt hiện vẻ khiếp sợ vì tận mắt thấy Khuất thú; các tông phái liền truyền lệnh cấm đệ tử bước vào phạm vi ngàn dặm quanh tháp."},{"chuong":"@c0477","importance":"normal","tieuDe":"Ra mắt Sứ giả tại Ngũ Linh Sơn","text":"Lão đang ngồi khoanh chân trên đỉnh Ngũ Linh Sơn hấp thu thái âm lực thì Vương Lâm tìm đến. Lão mở mắt bình tĩnh nói ra mắt Sứ giả đại nhân, Vương Lâm ôm quyền đáp lời."},{"bridge":true,"khoang":"@c0478","text":"Tự trách vì để lão đạo phá quy củ tiến vào phạm vi ngàn dặm quanh Thông Thiên Tháp, kinh động Khuất thú khiến Vương Lâm không thu phục được; cung kính trao Vương Lâm ngọc giản ghi ba chỗ yêu thú tụ tập, nhận ra giữa mi tâm hắn ẩn sát khí và đoán hắn đi vì giết chóc."}],"tuViMoc":[{"chuong":"@c0477","canhGioi":"Anh Biến hậu kỳ đại viên mãn","text":"Tu vi cao nhất Linh Nhạc quốc, gần như đặt một chân vào cảnh giới Vấn Đỉnh.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Tân Sứ giả Huyền Uyên Phái mà lão thăm dò rồi khiếp sợ; cuối chương Vương Lâm tìm đến lão tại Ngũ Linh Sơn","ghiChu":"@c0477"},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Tôn xưng Sứ giả đại nhân, phục vụ và trao ngọc giản","ghiChu":""}],"tuiDo":{}},"nguon":["@c0477","@c0478"]},{"id":"quach-ta-dat","name":"Quách Tà Dật","aliases":["Quách đại sư huynh"],"gioiTinh":"nam","theLuc":[{"ten":"Đại La Kiếm Tông","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Lục đại đệ tử Đại La Kiếm Tông, đại sư huynh của nhóm năm người tới Địa Ma Bắc Giới.","vaiTro":"Đệ tử kiếm tu Đại La Kiếm Tông","tinhCach":[{"text":"Khéo léo, dùng thủ đoạn mượn danh sư môn để chiếm lợi","chuong":"@c0478"}],"tabs":{"diem":[{"text":"Mượn danh Đại La Kiếm Tông và lời mời trợ trận để chiếm Diệu Kim quả","chuong":"@c0478"}],"kinhLich":[{"chuong":"@c0478","importance":"normal","tieuDe":"Dẫn nhóm tới Địa Ma Bắc Giới","text":"Trung tuần mặc trường sam trắng xanh đeo trường kiếm cổ, làm đại sư huynh nhóm năm người, bảo chờ Sư bá rồi mới tiến vào; mâu thuẫn với Thiên Cầm cô nương về Diệu Kim quả, rồi cung kính tham kiến lão sư thúc Hoá Thần hậu kỳ và quỳ một gối ra mắt hai Kiếm Các Trưởng lão."},{"chuong":"@c0479","importance":"normal","tieuDe":"Khai báo việc phát hiện Diệu Kim quả","text":"Là tu sĩ Đại La Kiếm Tông, Quách Tà Dật khai với hai Trưởng lão về việc sư môn Thiên Cầm phát hiện Diệu Kim quả, chỉ về phía nàng và cầu xin cho nàng một quả sau khi thu được. Sau đó hắn ân cần bắt chuyện muốn hàn gắn với Thiên Cầm."},{"chuong":"@c0481","importance":"normal","tieuDe":"Dựng cục hại sư huynh Thiên Cầm","text":"Là kẻ dựng nên việc đẩy sư huynh Thiên Cầm vào sơn cốc Cửu Lê trùng; nắm chặt bảo kiếm trong tay áo, lóe sát khí về phía Thiên Cầm và thừa nhận hai bên đã kết thù."}],"tuViMoc":[{"chuong":"@c0478","canhGioi":"Kết Đan trở lên","text":"Đại đệ tử dẫn đầu nhóm, tu vi cao hơn các sư đệ sư muội Kết Đan","importance":"minor"}],"nhanMach":[{"ten":"Thiên Cầm cô nương","tag":"doi-thu","quanHe":"Được nàng mời trợ trận nhưng chiếm Diệu Kim quả, bị nàng căm hận","ghiChu":""},{"ten":"Lão già Hoá Thần hậu kỳ (sư thúc Quách Tà Dật)","tag":"su-mon","quanHe":"Sư thúc, dẫn ra mắt hai Trưởng lão","ghiChu":""},{"ten":"Thiên Cầm cô nương","tag":"khac","quanHe":"Người hắn khai ra rồi muốn hàn gắn","ghiChu":"Hắn khiến nàng bị ép dẫn đường rồi xin cho nàng một quả, sau ân cần bắt chuyện."},{"ten":"Lão già cao người (Trưởng lão Đại La Kiếm Tông)","tag":"su-mon","quanHe":"Trưởng lão tông môn","ghiChu":"Tra hỏi hắn và đồng ý cho Thiên Cầm một quả."},{"ten":"Lão già thấp người (Trưởng lão Đại La Kiếm Tông)","tag":"su-mon","quanHe":"Trưởng lão tông môn","ghiChu":"Hỏi hắn số lượng Diệu Kim quả."},{"ten":"Thiên Cầm","tag":"doi-thu","quanHe":"Kết thù sau khi hại chết sư huynh nàng","ghiChu":"@c0481"},{"ten":"Lữ Tùng Nghĩa","tag":"su-mon","quanHe":"Sư thúc, lão già Hóa Thần kỳ đi cùng","ghiChu":"@c0481"},{"ten":"Nữ tử (sư muội Quách Tà Dật)","tag":"su-mon","quanHe":"Sư muội đi cùng, gọi hắn là sư huynh","ghiChu":"@c0481"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0478","@c0479","@c0481"]},{"id":"thien-cam-co-nuong","name":"Thiên Cầm cô nương","gioiTinh":"nu","theLuc":[],"trangThai":"song","blurb":"Nữ tử xinh đẹp mời Quách Tà Dật trợ trận nhưng bị hắn mượn danh sư môn chiếm Diệu Kim quả.","vaiTro":"Nữ tu tranh chấp Diệu Kim quả","tinhCach":[{"text":"Đầy thù hận, thẳng thắn mắng kẻ dùng thủ đoạn đê tiện","chuong":"@c0478"}],"tabs":{"diem":[{"text":"Căm hận Quách Tà Dật vì bị chiếm đoạt Diệu Kim quả","chuong":"@c0478"}],"kinhLich":[{"chuong":"@c0478","importance":"normal","tieuDe":"Tranh chấp Diệu Kim quả","text":"Mặc quần lụa trắng thắt nơ bướm tơ tằm, mắng Quách Tà Dật mượn danh Đại La Kiếm Tông dùng thủ đoạn đê tiện; được hắn hứa để lại một quả Diệu Kim quả mang về sư môn."},{"chuong":"@c0479","importance":"normal","tieuDe":"Bị ép dẫn đường vào Địa Ma Bắc Giới","text":"Bị Quách Tà Dật khai ra việc sư môn nàng phát hiện Diệu Kim quả, Thiên Cầm bị hai Trưởng lão Anh Biến sơ kỳ của Đại La Kiếm Tông ép dẫn đường vào Địa Ma Bắc Giới. Nội tâm chua xót hận Quách Tà Dật phản bội, nhưng vì khí tức hai Trưởng lão vượt xa sư môn nhỏ bé của nàng, nàng đành cắn răng cam chịu, chỉ mong đạt được một Diệu Kim quả."},{"bridge":true,"khoang":"@c0480","text":"Dẫn đường cho đoàn Đại La Kiếm Tông tới sơn cốc nơi sư môn vãn bối phát hiện Diệu Kim quả hai tháng trước, rồi lui về sau; bị lão già Hoá Thần kỳ liếc nhìn thân thể với quang mang kỳ lạ."},{"chuong":"@c0481","importance":"normal","tieuDe":"Mất sư huynh trong sơn cốc","text":"Chứng kiến sư huynh áo trắng bị Cửu Lê trùng chui vào cơ thể ăn thịt đến chết, nàng chấn động gặng hỏi tiền bối vì sao, nở nụ cười thê thảm rồi chuyển sang bình tĩnh đáng sợ."}],"tuViMoc":[],"nhanMach":[{"ten":"Quách Tà Dật","tag":"doi-thu","quanHe":"Mời trợ trận nhưng bị chiếm Diệu Kim quả, sinh thù hận","ghiChu":""},{"ten":"Quách Tà Dật","tag":"doi-thu","quanHe":"Từng tin tưởng, nay hận vì bị phản bội","ghiChu":"Quách Tà Dật khai ra việc sư môn nàng phát hiện Diệu Kim quả khiến nàng bị ép dẫn đường; sau đó hắn ân cần muốn hàn gắn nhưng nàng càng chua xót."},{"ten":"Lão già cao người (Trưởng lão Đại La Kiếm Tông)","tag":"doi-thu","quanHe":"Kẻ ép nàng dẫn đường","ghiChu":"Đồng ý cho nàng một quả sau khi thu được, ra lệnh dẫn đường."},{"ten":"Nam tử áo trắng (đồng môn Thiên Cầm)","tag":"su-mon","quanHe":"Cùng sư môn","ghiChu":"Đồng môn tức giận thay nàng nhưng bị nàng quát im."},{"ten":"Nam tử áo trắng (đồng môn Thiên Cầm)","tag":"su-mon","quanHe":"Sư huynh, bị hại chết trong sơn cốc","ghiChu":"@c0481"},{"ten":"Quách Tà Dật","tag":"doi-thu","quanHe":"Kẻ dựng cục đẩy sư huynh nàng vào cốc, kết thù","ghiChu":"@c0481"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0478","@c0479","@c0480","@c0481"]},{"id":"lao-gia-hoa-than-su-thuc-quach-ta-dat","name":"Lão già Hoá Thần hậu kỳ (sư thúc Quách Tà Dật)","gioiTinh":"nam","theLuc":[{"ten":"Đại La Kiếm Tông","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Một trong ba lão tóc bạc hắc y đeo bảo kiếm cổ, tu vi Hoá Thần hậu kỳ, sư thúc của Quách Tà Dật.","vaiTro":"Trưởng bối Đại La Kiếm Tông","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c0478","importance":"normal","tieuDe":"Giáng lâm Địa Ma Bắc Giới","text":"Cùng hai Kiếm Các Trưởng lão lao tới bằng trường hồng, khí lãng thổi bay những người khác lui hơn mười trượng; dẫn Quách Tà Dật ra mắt hai Trưởng lão."},{"bridge":true,"khoang":"@c0480","text":"Trong đoàn tiến vào Địa Ma Bắc Giới, thỉnh thoảng liếc nhìn thân thể yêu kiều của Thiên Cầm với quang mang kỳ lạ, lộ ý đồ; không nhận ra sự kinh hoàng của hai Trưởng lão trước áp lực quỷ dị."}],"tuViMoc":[{"chuong":"@c0478","canhGioi":"Hoá Thần hậu kỳ","text":"Tu vi Hoá Thần hậu kỳ","importance":"minor"}],"nhanMach":[{"ten":"Quách Tà Dật","tag":"su-mon","quanHe":"Là sư thúc, dẫn ra mắt hai Trưởng lão","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0478","@c0480"],"aliases":["Lão già Hoá Thần hậu kỳ (sư thúc Quách Tà Dật)"]},{"id":"hai-kiem-cac-truong-lao","name":"Hai Kiếm Các Trưởng lão","gioiTinh":"nam","theLuc":[{"ten":"Đại La Kiếm Tông","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Hai lão già hắc y tu vi Anh Biến sơ kỳ đeo bảo kiếm cổ, Trưởng lão Kiếm Các của Đại La Kiếm Tông.","vaiTro":"Trưởng lão Kiếm Các Đại La Kiếm Tông","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c0478","importance":"normal","tieuDe":"Ra mắt tại Địa Ma Bắc Giới","text":"Lao tới cùng lão Hoá Thần hậu kỳ, được Quách Tà Dật quỳ một gối tham kiến."}],"tuViMoc":[{"chuong":"@c0478","canhGioi":"Anh Biến sơ kỳ","text":"Cả hai tu vi Anh Biến sơ kỳ","importance":"minor"}],"nhanMach":[{"ten":"Quách Tà Dật","tag":"su-mon","quanHe":"Được Quách Tà Dật quỳ tham kiến","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0478"]},{"id":"thieu-nu-ket-dan-dai-la-kiem-tong","name":"Thiếu nữ Kết Đan hậu kỳ (Đại La Kiếm Tông)","gioiTinh":"nu","theLuc":[{"ten":"Đại La Kiếm Tông","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Một trong hai nữ tử nhóm Quách Tà Dật, tu vi Kết Đan hậu kỳ, báo có người tiến vào Địa Ma Bắc Giới.","vaiTro":"Đệ tử Đại La Kiếm Tông","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"bridge":true,"khoang":"@c0478","text":"Mặc quần lụa miệng xinh, báo với nhóm thấy có người vừa tiến vào Địa Ma Bắc Giới."}],"tuViMoc":[{"chuong":"@c0478","canhGioi":"Kết Đan hậu kỳ","text":"Tu vi Kết Đan hậu kỳ","importance":"minor"}],"nhanMach":[{"ten":"Quách Tà Dật","tag":"su-mon","quanHe":"Đại sư huynh dẫn đầu nhóm","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0478"]},{"id":"nam-tu-ao-lam-dai-la-kiem-tong","name":"Nam tử áo lam (Đại La Kiếm Tông)","gioiTinh":"nam","theLuc":[{"ten":"Đại La Kiếm Tông","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Đệ tử trẻ chừng hai mươi bảy tám tuổi nịnh hót, đề cao Đại La Kiếm Tông và Quách Tà Dật.","vaiTro":"Đệ tử Đại La Kiếm Tông","tinhCach":[{"text":"Nịnh hót, tâng bốc đại sư huynh và sư môn","chuong":"@c0478"}],"tabs":{"diem":[],"kinhLich":[{"bridge":true,"khoang":"@c0478","text":"Khen Đại La Kiếm Tông là môn phái số một số hai Thiên Vận Tinh và đề cao Quách Tà Dật."},{"chuong":"@c0481","importance":"minor","tieuDe":"Say mê cảnh tàn khốc","text":"Kẻ được Quách Tà Dật nịnh hót; trong khi mọi người kinh sợ, hắn lại thầm say mê cảnh tượng nam tử áo trắng bị Cửu Lê trùng ăn thịt."}],"tuViMoc":[],"nhanMach":[{"ten":"Quách Tà Dật","tag":"su-mon","quanHe":"Đại sư huynh được hắn tâng bốc","ghiChu":""},{"ten":"Quách Tà Dật","tag":"khac","quanHe":"Được Quách Tà Dật nịnh hót","ghiChu":"@c0481"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0478","@c0481"]},{"id":"lao-gia-cao-nguoi-dai-la-kiem-tong","name":"Lão già cao người (Trưởng lão Đại La Kiếm Tông)","cn":"","aliases":["Trưởng lão cao người Đại La Kiếm Tông","Lão già cao người (Trưởng lão Đại La Kiếm Tông)","Lão già cao họ Thạch","Thạch Phương Trưởng lão"],"gioiTinh":"nam","theLuc":[{"ten":"Đại La Kiếm Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến sơ kỳ","trangThai":"song","blurb":"Một trong hai Trưởng lão Anh Biến sơ kỳ của Đại La Kiếm Tông tham gia chuyến tìm Diệu Kim quả.","vaiTro":"Trưởng lão tra hỏi và ép dẫn đường","tinhCach":[{"text":"Hống hách nhưng còn giữ lời, đồng ý cho Thiên Cầm một quả.","chuong":"@c0479"}],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c0479","importance":"normal","tieuDe":"Ép Thiên Cầm dẫn đường tìm Diệu Kim quả","text":"Cùng lão già thấp người tra hỏi Quách Tà Dật về Diệu Kim quả, đồng ý cho Thiên Cầm một quả sau khi thu được rồi ra lệnh cho nàng dẫn đoàn vào Địa Ma Bắc Giới."},{"chuong":"@c0480","importance":"normal","tieuDe":"Mở thông đạo vào sơn cốc Diệu Kim quả","text":"Trưởng lão Anh Biến sơ kỳ Thạch Phương cảm nhận áp lực quỷ dị như vạn sơn áp đỉnh trong Địa Ma Bắc Giới — cảm giác chưa từng gặp từ khi Hoá Thần — song vẫn quyết đi nhanh hơn. Tới sơn cốc, lão bấm quyết ngưng tụ một chiếc côn nồng đậm tiên lực hoá tiên phong thổi tan cây cối, mở thông đạo lộ ra phiến Diệu Kim quả, rồi nhận ra ổ Cửu Lê trùng ẩn dưới lá khô gần đó."},{"chuong":"@c0481","importance":"normal","tieuDe":"Phong ấn Cửu Lê trùng, đối đầu bụi khí","text":"Xưng danh Trưởng lão Đại La Kiếm Tông, dùng cấm thuật Kiếm phong chi cấm qua ngọc giản đỏ phong ấn nam tử áo trắng cùng đàn Cửu Lê trùng. Khi kẻ mạnh trong bụi khí xuất hiện, bấm quyết hóa bóng kiếm hư ảo hơn mười trượng chém xuống, nhưng kiếm bị đợt bụi khí phá tan."}],"tuViMoc":[],"nhanMach":[{"ten":"Lão già thấp người (Trưởng lão Đại La Kiếm Tông)","tag":"dong-minh","quanHe":"Đồng liêu cùng tông","ghiChu":"Hai Trưởng lão cùng tham gia chuyến tìm Diệu Kim quả."},{"ten":"Quách Tà Dật","tag":"su-mon","quanHe":"Tu sĩ cùng tông bị tra hỏi","ghiChu":"Tra hỏi hắn về Diệu Kim quả."},{"ten":"Thiên Cầm cô nương","tag":"doi-thu","quanHe":"Người bị ép dẫn đường","ghiChu":"Ra lệnh nàng dẫn đường, hứa cho một quả."},{"ten":"Lão già thấp người (Trưởng lão Đại La Kiếm Tông)","tag":"dong-minh","quanHe":"Cùng là Trưởng lão Đại La Kiếm Tông, phối hợp ăn ý","ghiChu":"@c0481"},{"ten":"Người trong bụi khí (giọng lạnh lẽo)","tag":"doi-thu","quanHe":"Kẻ mạnh phá tan kiếm của hắn","ghiChu":"@c0481"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0479","@c0480","@c0481"]},{"id":"lao-gia-thap-nguoi-dai-la-kiem-tong","name":"Lão già thấp người (Trưởng lão Đại La Kiếm Tông)","cn":"","aliases":["Trưởng lão thấp người Đại La Kiếm Tông","Lão già thấp người (Trưởng lão Đại La Kiếm Tông)"],"gioiTinh":"nam","theLuc":[{"ten":"Đại La Kiếm Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến sơ kỳ","trangThai":"song","blurb":"Một trong hai Trưởng lão Anh Biến sơ kỳ của Đại La Kiếm Tông, mắt bừng tinh quang khi nghe Diệu Kim quả có khoảng trăm quả.","vaiTro":"Trưởng lão tham lam Diệu Kim quả","tinhCach":[{"text":"Tham lam, mắt bừng tinh quang khi nghe số lượng Diệu Kim quả.","chuong":"@c0479"}],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c0479","importance":"normal","tieuDe":"Hỏi số lượng Diệu Kim quả","text":"Hỏi Thiên Cầm số lượng Diệu Kim quả; nghe đáp ước chừng trăm quả thì mắt bừng tinh quang, lộ rõ tham vọng."},{"chuong":"@c0480","importance":"normal","tieuDe":"Ném đồng môn thử Cửu Lê trùng","text":"Trưởng lão Anh Biến sơ kỳ cảm giác kích động muốn giết người khi gặp Khổ Ảnh thú, từng đề nghị rời đi. Tới sơn cốc, lão chỉ ra cần dược dẫn đối phó Cửu Lê trùng rồi bất ngờ dùng lực vô hình chụp lấy gã đồng môn áo trắng bên người Thiên Cầm, ném thẳng vào sơn cốc làm mồi, lộ nụ cười tàn nhẫn."},{"chuong":"@c0481","importance":"normal","tieuDe":"Dọn trùng, sai hái Diệu Kim quả","text":"Tiến vào sơn cốc trước, bắn kiếm khí diệt sạch Cửu Lê trùng còn sót, ra lệnh cho Lữ Tùng Nghĩa đi hái Diệu Kim quả. Khi bụi khí áp tới, ném ra gương đồng một mặt tỏa thanh quang chống đỡ, nhưng gương bị giọng lạnh lẽo phá vỡ răng rắc."}],"tuViMoc":[],"nhanMach":[{"ten":"Lão già cao người (Trưởng lão Đại La Kiếm Tông)","tag":"dong-minh","quanHe":"Đồng liêu cùng tông","ghiChu":"Hai Trưởng lão cùng tham gia chuyến tìm Diệu Kim quả."},{"ten":"Thiên Cầm cô nương","tag":"doi-thu","quanHe":"Người bị tra hỏi số lượng quả","ghiChu":"Hỏi nàng số lượng Diệu Kim quả."},{"ten":"Lữ Tùng Nghĩa","tag":"dong-minh","quanHe":"Sai đi hái Diệu Kim quả","ghiChu":"@c0481"},{"ten":"Người trong bụi khí (giọng lạnh lẽo)","tag":"doi-thu","quanHe":"Kẻ mạnh phá vỡ gương đồng của lão","ghiChu":"@c0481"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0479","@c0480","@c0481"]},{"id":"nam-tu-ao-trang-dong-mon-thien-cam","name":"Nam tử áo trắng (đồng môn Thiên Cầm)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Sư môn của Thiên Cầm","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không-ro","trangThai":"song","blurb":"Tu sĩ cùng sư môn với Thiên Cầm, tức giận trách Đại La Kiếm Tông nhưng bị Thiên Cầm quát im.","vaiTro":"Đồng môn bất bình của Thiên Cầm","tinhCach":[{"text":"Nóng nảy, bất bình thay sư môn nhưng phải nhẫn nhịn.","chuong":"@c0479"}],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c0479","importance":"normal","tieuDe":"Bất bình trách Đại La Kiếm Tông","text":"Tức giận trách Đại La Kiếm Tông về việc sư môn phải hy sinh nhiều trưởng bối mới tìm được Diệu Kim quả, nhưng bị Thiên Cầm quát ‘Câm mồm!’ buộc phải im lặng nhẫn nhịn."},{"bridge":true,"khoang":"@c0480","text":"Bị lão già thấp người dùng lực vô hình chụp lấy và ném thẳng vào sơn cốc làm dược dẫn thử Cửu Lê trùng; vừa tiến vào liền bị vô số điểm đỏ Cửu Lê trùng lao tới."},{"chuong":"@c0481","importance":"normal","tieuDe":"Bị Cửu Lê trùng ăn thịt đến chết","text":"Bị ném vào giữa sơn cốc, vô số Cửu Lê trùng phá quần áo chui vào da thịt; chưa đến ba tức toàn thân lộ huyết sắc, hắn tự cào cấu da thịt lộ cả xương cốt, dãy dụa thảm thiết rồi tắt tiếng, hai mắt ảm đạm tuyệt vọng oán hận."}],"tuViMoc":[],"nhanMach":[{"ten":"Thiên Cầm cô nương","tag":"su-mon","quanHe":"Cùng sư môn","ghiChu":"Bị nàng quát im khi tức giận trách Đại La Kiếm Tông."},{"ten":"Thiên Cầm","tag":"su-mon","quanHe":"Sư muội chứng kiến hắn chết","ghiChu":"@c0481"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0479","@c0480","@c0481"]},{"id":"lu-tung-nghia","name":"Lữ Tùng Nghĩa","gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Hóa Thần kỳ","trangThai":"song","blurb":"Lão già Hóa Thần kỳ, sư thúc của Quách Tà Dật, được sai vào sơn cốc Địa Ma Bắc giới hái Diệu Kim quả.","vaiTro":"Trợ thủ trong nhóm Quách Tà Dật và hai Trưởng lão Đại La Kiếm Tông, đảm nhận việc hái Diệu Kim quả.","tinhCach":[{"text":"Tuân lệnh, hành động dứt khoát, lao như điện về phía Diệu Kim quả khi được sai.","chuong":"@c0481"}],"tabs":{"diem":[{"text":"Lão già Hóa Thần kỳ, vai vế sư thúc của Quách Tà Dật.","chuong":"@c0481"}],"kinhLich":[{"chuong":"@c0481","importance":"normal","tieuDe":"Vào cốc hái Diệu Kim quả","text":"Vào sơn cốc thứ ba sau hai Trưởng lão, được lão già lùn ra lệnh đi hái Diệu Kim quả. Khi biến cố bụi khí nổ ra, lão lao như điện tới được bên cạnh đóa hoa trên tảng đá vàng."}],"tuViMoc":[{"chuong":"@c0481","canhGioi":"Hóa Thần kỳ","text":"Xuất hiện với cảnh giới Hóa Thần kỳ.","importance":"minor"}],"nhanMach":[{"ten":"Quách Tà Dật","tag":"su-mon","quanHe":"Cháu (sư điệt)","ghiChu":"@c0481"},{"ten":"Lão già lùn (Trưởng lão Đại La Kiếm Tông)","tag":"dong-minh","quanHe":"Nhận lệnh hái Diệu Kim quả","ghiChu":"@c0481"}],"tuiDo":{}},"nguon":["@c0481"]},{"id":"nu-tu-su-muoi-quach-ta-dat","name":"Nữ tử (sư muội Quách Tà Dật)","gioiTinh":"nu","trangThai":"song","blurb":"Nữ tử gọi Quách Tà Dật là sư huynh; tái nhợt run rẩy trước cảnh tàn khốc trong sơn cốc.","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0481","importance":"minor","tieuDe":"Kinh sợ trước cảnh tàn khốc","text":"Đi cùng nhóm Quách Tà Dật, sắc mặt tái nhợt và run rẩy vì kinh sợ khi chứng kiến nam tử áo trắng bị Cửu Lê trùng ăn thịt."}],"tuViMoc":[],"nhanMach":[{"ten":"Quách Tà Dật","tag":"su-mon","quanHe":"Sư huynh","ghiChu":"@c0481"}],"tuiDo":{}},"nguon":["@c0481"]},{"id":"nguoi-trong-bui-khi-giong-lanh-leo","name":"Người trong bụi khí (giọng lạnh lẽo)","gioiTinh":"khong-ro","trangThai":"khong-ro","blurb":"Kẻ mạnh ẩn trong đoàn bụi khí nồng đậm, thực lực áp đảo hai Trưởng lão Đại La Kiếm Tông; danh tính chưa rõ.","tabs":{"diem":[{"text":"Ẩn trong bụi khí, chỉ một câu nói và một đợt bụi khí đã phá vỡ gương đồng và kiếm của hai Trưởng lão.","chuong":"@c0481"}],"kinhLich":[{"chuong":"@c0481","importance":"normal","tieuDe":"Áp đảo hai Trưởng lão Đại La Kiếm Tông","text":"Xuất hiện sau cơn gió mát khiến hai Trưởng lão đại biến sắc mặt. Đoàn bụi khí nồng đậm bùng lên như vạn mã, phá tan thanh quang gương đồng và kiếm khí Thạch Phương; từ trong bụi khí truyền ra giọng lạnh lẽo: “Ánh sáng của đom đóm há có thể so sánh với ánh trăng!”"}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Phương","tag":"doi-thu","quanHe":"Phá tan kiếm của Thạch Phương","ghiChu":"@c0481"},{"ten":"Lão già lùn (Trưởng lão Đại La Kiếm Tông)","tag":"doi-thu","quanHe":"Phá vỡ gương đồng của lão","ghiChu":"@c0481"}],"tuiDo":{}},"nguon":["@c0481"]}]};
